import axios from '@fs/zion-axios'
import { sgBaseUrl } from '@fs/zion-config'
import { getUser } from '@fs/zion-user'
import { getAnonSession } from '@fs/zion-session'
import { type ImageAttribution } from './imageAttributionTypes'

async function convertArkToApid(ark: string): Promise<string> {
  const { data } = await axios.get(`${sgBaseUrl}/service/records/storage/dascloud/das/v2/${ark}/name?namespace=apid`, {
    headers: {
      accept: 'text/plain',
    },
    responseType: 'text',
  })
  return data
}

export interface ImageMetaData extends ImageAttribution {
  error?: string
}

export default async function getImageMetaData(imageApidOrArk: string): Promise<ImageMetaData> {
  const defaultMetaData: ImageMetaData = {
    id: '',
    attributions: [],
    patronNotifications: [],
    download: false,
    print: false,
  }

  try {
    const user = await getUser()
    if (!user) {
      await getAnonSession()
    }
  } catch (error) {
    console.error('Authentication error, removing download and print permissions')
    defaultMetaData.error = 'Authentication error'
  }
  try {
    let resolvedId = imageApidOrArk
    if (imageApidOrArk.startsWith('3:1:3')) resolvedId = await convertArkToApid(imageApidOrArk)

    const response = await axios.get(`${sgBaseUrl}/service/records/hermes/project/${resolvedId}`)

    const data = response?.data
    if (!data || typeof data !== 'object') {
      throw new Error('Invalid response structure from API')
    }

    const attributions = Array.isArray(data.attributions) ? data.attributions : []

    return {
      id: resolvedId,
      attributions,
      patronNotifications: Array.isArray(data.patronNotifications) ? data.patronNotifications : [],
      download: Boolean(data.download),
      print: Boolean(data.print),
    }
  } catch (error) {
    console.error('Error fetching image metadata:', error)
  }
  return { ...defaultMetaData, error: 'Unable to verify image permissions' }
}
