import type { ReactElement } from 'react'
import React, { useReducer, useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import type { ZoomPanRefs, ZoomPanProps } from '@fs/zion-ui'
import { ZoomPanControlButton, ZoomPanViewerHud, useOverlay, useZoomPan, colors } from '@fs/zion-ui'
import { ControlSettingsAdjust, ContentDownload } from '@fs/zion-icon'
import getImageMetaData, { type ImageMetaData } from '../utils/getImageMetaData'
import { parseImageArkFromUrl } from '../utils/parseImageArks'

import { reducer as adjustmentsReducer, initialState as initialAdjustmentsState } from './adjustments/reducer'
import Adjustments from './adjustments/Adjustments'
import type { SingleImageViewerBaseProps } from './SingleImageViewerBase'
import SingleImageViewerBase from './SingleImageViewerBase'
import { onDownload as defaultOnDownload } from './downloadHelper'
import { AttributionProvider } from '../components/ImageAttribution/AttributionContext'

type CommonProps = SingleImageViewerBaseProps &
  Omit<ZoomPanProps, keyof ZoomPanRefs> & {
    disableAdjustments?: boolean
    downloadControl?: boolean
    onDownload?: (src: string) => void
    adjustmentControls?: ReactElement | ReactElement[] | null
  }

type ControlledProps = CommonProps & ZoomPanRefs

function GrayContentDownload(): JSX.Element {
  return <ContentDownload color={colors.gray50} />
}

const ControlledSingleImageViewer = ({
  alt,
  src,

  fill = false,
  drawingMode = false,
  forceDeepZoom = false,
  getDeepZoomInfoCallback,

  controllerRef,
  viewerRef,
  stageRef,

  adjustmentControls,
  controls,
  disableAdjustments,
  downloadControl,
  onDownload = defaultOnDownload,
  overLayer,
  ...props
}: ControlledProps): JSX.Element => {
  const { t } = useTranslation()
  const [adjustments, adjustmentsDispatch] = useReducer(
    adjustmentsReducer,
    initialAdjustmentsState,
    (initialState) => ({ ...initialState, initialMaintainZoomPan: initialState.initialMaintainZoomPan })
  )

  const quickGlanceOverlay = useOverlay()
  // handleQuickGlanceClick toggles between open/close
  const { handleClick: handleQuickGlanceClick } = quickGlanceOverlay

  const { brightness, contrast, invert } = adjustments

  // Parse imageArk from src URL
  const imageArk = parseImageArkFromUrl(src)

  // Fetch image metadata for download restrictions only
  const [imageMetaData, setImageMetaData] = useState<ImageMetaData | null>(null)

  useEffect(() => {
    let cancelled = false

    async function fetchMetadata(): Promise<void> {
      if (imageArk) {
        try {
          const data = await getImageMetaData(imageArk)
          if (!cancelled) {
            setImageMetaData(data)
          }
        } catch (error) {
          if (!cancelled) {
            console.error('Failed to fetch image metadata:', error)
            setImageMetaData(null)
          }
        }
      }
    }

    fetchMetadata()

    return () => {
      cancelled = true
    }
  }, [imageArk])

  const canDownload = imageMetaData?.download === true

  return (
    <>
      <SingleImageViewerBase
        alt={alt}
        src={src}
        forceDeepZoom={forceDeepZoom}
        getDeepZoomInfoCallback={getDeepZoomInfoCallback}
        controllerRef={controllerRef}
        viewerRef={viewerRef}
        stageRef={stageRef}
        brightness={brightness}
        contrast={contrast}
        invert={invert}
        fill={fill}
        drawingMode={drawingMode}
        overLayer={
          <>
            <ZoomPanViewerHud
              controllerRef={controllerRef}
              showResetControl
              zoomable
              controls={
                <>
                  {!disableAdjustments && (
                    <ZoomPanControlButton
                      data-testid="adjustments-button"
                      label={t('image-viewer.toolbar.toggle-controls.button', 'Adjust Image')}
                      Icon={ControlSettingsAdjust}
                      onClick={handleQuickGlanceClick}
                    />
                  )}
                  {controls}
                  {downloadControl && canDownload && (
                    <ZoomPanControlButton
                      data-testid="download-image-button"
                      label={t('image-viewer.toolbar.download.button', 'Download')}
                      Icon={ContentDownload}
                      onClick={() => onDownload(src)}
                    />
                  )}
                  {downloadControl && !canDownload && (
                    <ZoomPanControlButton
                      data-testid="download-image-button-disabled"
                      label={t(
                        'image-viewer.toolbar.download.disabled',
                        'Due to contract restrictions this feature is disabled'
                      )}
                      Icon={GrayContentDownload}
                      onClick={() => {
                        /* No-op: Button is disabled via styling only */
                      }}
                    />
                  )}
                </>
              }
            />
            {overLayer}
          </>
        }
        {...props}
      />
      {!disableAdjustments && (
        <Adjustments
          adjustmentControls={adjustmentControls}
          controllerRef={controllerRef}
          quickGlanceOverlay={quickGlanceOverlay}
          adjustmentsDispatch={adjustmentsDispatch}
          adjustments={adjustments}
          hideMaintainZoomPan
          hideShortcutLeftRightArrows
          hideShortcutDownloadControl={!downloadControl}
        />
      )}
    </>
  )
}

export const UncontrolledSingleImageViewer = (props: CommonProps): JSX.Element => {
  const [{ viewerRef, stageRef, controllerRef }] = useZoomPan()
  return (
    <ControlledSingleImageViewer viewerRef={viewerRef} stageRef={stageRef} controllerRef={controllerRef} {...props} />
  )
}

function isControlledImageViewer(props: ControlledProps | CommonProps): props is ControlledProps {
  return (props as ControlledProps).controllerRef !== undefined
}

const SingleImageViewer = (props: ControlledProps | CommonProps): JSX.Element => {
  return (
    <AttributionProvider>
      {isControlledImageViewer(props) ? (
        <ControlledSingleImageViewer {...props} />
      ) : (
        <UncontrolledSingleImageViewer {...props} />
      )}
    </AttributionProvider>
  )
}

export default SingleImageViewer
