import React, { useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { colors, H2, Image, LayoutBand, Paragraph, Row, Separator } from '@fs/zion-ui'
import UnauthorizedSvg from '../assets/unauthorized.svg'

type Props = {
  permissions?: string
}

const LimitedAccessMessage = ({ permissions }: Props): JSX.Element => {
  const [t] = useTranslation()

  const PERMISSION_MAP = useMemo(
    () => ({
      ThemisPrmAffiliate: t('limitedAccessMessage.permissions.themisPrmAffiliate', 'At an Affiliate Library'),
      ThemisPrmFhlc: t('limitedAccessMessage.permissions.themisPrmFhlc', 'At a FamilySearch Center'),
      ThemisPrmFhlSLC: t(
        'limitedAccessMessage.permissions.themisPrmFhlSLC',
        'At the Salt Lake City Family History Library'
      ),
      ThemisPrmLdsMember: t(
        'limitedAccessMessage.permissions.themisPrmLdsMember',
        'A member of a supporting organization'
      ),
    }),
    [t]
  )

  const permissionsList = permissions
    ?.split(':')
    ?.map((perm) => PERMISSION_MAP[perm])
    ?.filter(Boolean)

  return (
    <LayoutBand color={colors.gray03} maxWidth="xs" style={{ minHeight: '100%' }}>
      <Separator size="lg" />
      <H2 size="H3" centered>
        {t('limitedAccessMessage.heading', 'Limited Access Image')}
      </H2>
      <Separator size="nano" />
      <Paragraph balanced>
        {t(
          'limitedAccessMessage.description',
          'Access is limited due to agreements with the record owner or legal restrictions based on location or organization membership. You can view it if you are:'
        )}
      </Paragraph>
      <Separator size="xs" />
      <Paragraph as="div">
        <ul>
          {permissionsList?.map((permission) => (
            <li key={permission}>{permission}</li>
          ))}
        </ul>
      </Paragraph>
      <Separator size="md" />
      <Row alignX="center">
        <Image
          src={UnauthorizedSvg}
          alt={t('limitedAccessMessage.heading', 'Limited Access Image')}
          style={{ maxWidth: '750px' }}
        />
      </Row>
    </LayoutBand>
  )
}

export default LimitedAccessMessage
