import React, {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useCallback,
  useState,
  useRef,
  type ReactNode,
} from 'react'
import { useOverlay, type UseOverlayReturnOptions } from '@fs/zion-ui'
import Cache from '@fs/zion-cache'
import { getSessionId } from '@fs/zion-session'
import { useQueryParams } from '@fs/zion-router'
import useImageMetaData from './useImageMetaData'
import { parseImageArkFromUrl } from '../../utils/parseImageArks'

type Attribution = {
  language?: string
  archiveName?: string
  contactInfo?: string
  url?: string
  notes?: string | null
}

type AttributionData = {
  attributions: Attribution[]
  downloadAllowed?: boolean
}

type AttributionContextValue = {
  attribution: AttributionData | null
  loading: boolean
  error: string | null
  openAttribution: () => void
  closeAttribution: () => void
  overlay: UseOverlayReturnOptions
}

const storeName = 'lightyear_imageAttributionsViewed'
const AttributionContext = createContext<AttributionContextValue | null>(null)

export function useAttributionContext(): AttributionContextValue | null {
  return useContext(AttributionContext)
}

type AttributionProviderProps = {
  children: ReactNode
}

export function AttributionProvider({ children }: AttributionProviderProps): JSX.Element {
  const overlay = useOverlay()
  const cache = useMemo(() => new Cache({ storeName }), [])
  const { query } = useQueryParams()
  const groupId = query?.groupId || null

  const url = typeof window === 'undefined' ? '' : window.location.href
  const imageArk = parseImageArkFromUrl(url)
  const sessionId = getSessionId()
  const viewedKey = groupId || imageArk

  const [viewedAttributions, setViewedAttributions] = useState<string[]>([])
  const [storedSession, setStoredSession] = useState<string>('')

  const hasFetchedCache = useRef(false)

  const hasBeenViewed = useMemo(() => {
    if (overlay.isOpen) return true
    if (hasFetchedCache.current) return viewedAttributions.includes(viewedKey)
    return true
  }, [overlay.isOpen, viewedAttributions, viewedKey])

  useEffect(() => {
    let cancelled = false

    async function getViewedAttributions(): Promise<void> {
      if (!hasFetchedCache.current && cache && sessionId) {
        const cachedItems = await cache.getItem('viewedAttributions')
        const viewed = cachedItems?.viewed || []
        const session = cachedItems?.storedSession

        if (!cancelled) {
          hasFetchedCache.current = true
          setViewedAttributions(viewed)
          setStoredSession(session)
        }
      }
    }

    getViewedAttributions()

    return () => {
      cancelled = true
    }
  }, [cache, sessionId])

  useEffect(() => {
    if (!hasBeenViewed && hasFetchedCache.current) overlay.open()
    if (storedSession && sessionId && storedSession !== sessionId) {
      cache.clear()
      setViewedAttributions([])
    }
  }, [cache, hasBeenViewed, overlay, sessionId, storedSession, viewedAttributions, viewedKey])

  const { data, loading, error } = useImageMetaData(imageArk)

  const openAttribution = useCallback(() => {
    overlay.open()
  }, [overlay])

  const closeAttribution = useCallback(() => {
    if (viewedKey && !viewedAttributions.includes(viewedKey)) {
      const newList = [...viewedAttributions, viewedKey]
      setViewedAttributions(newList)
      cache.updateItem('viewedAttributions', { sessionId, viewed: newList })
    }
    overlay.close()
  }, [viewedKey, viewedAttributions, overlay, cache, sessionId])

  const value = useMemo<AttributionContextValue>(
    () => ({
      attribution: data
        ? {
            attributions: data.attributions || [],
            downloadAllowed: data.download,
          }
        : null,
      loading,
      error,
      openAttribution,
      closeAttribution,
      overlay,
    }),
    [data, loading, error, openAttribution, closeAttribution, overlay]
  )

  return <AttributionContext.Provider value={value}>{children}</AttributionContext.Provider>
}
