import React from 'react'
import { css } from '@linaria/core'

const imageTileCss = css`
  display: block;
  position: absolute;
`

export type Tile = {
  src: string
  left: number
  top: number
  width: number
  height: number
}

const ImageTile = ({ tile }: { tile: Tile }): JSX.Element => {
  const [left, top, width, height] = [tile.left, tile.top, tile.width, tile.height].map((n) => `${n * 100}%`)
  // alt="" and aria-hidden because we do not want the screen reader announcing tiles
  return (
    <img
      className={imageTileCss}
      src={tile.src}
      style={{
        left,
        top,
        width,
        height,
      }}
      alt=""
      aria-hidden
    />
  )
}

export default ImageTile
