import React from 'react'
import { css } from '@linaria/core'

const color1 = 'rgba(173, 174, 174, 0.25)'
const color2 = 'rgba(173, 174, 174, 0.5)'

const loadingCss = css`
  position: absolute;
  top: 0;
  left: 0;
  background-color: ${color1};
  animation: shine-lines 1.5s infinite;
  will-change: background-color;

  @keyframes shine-lines {
    from {
      background-color: ${color1};
    }
    50% {
      background-color: ${color2};
    }
    to {
      background-color: ${color1};
    }
  }
`

const ImageSkeleton = ({ width, height }: { width: string | number; height: string | number }): JSX.Element => {
  return <div className={loadingCss} style={{ width, height }} />
}

export default ImageSkeleton
