import type { ReactNode } from 'react'
import React, { useEffect, useState } from 'react'
import { colors } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { Elevation, OpenCloseAnimation } from '@fs/zion-ui/quarks-authorized-use-only'

const wrapperCss = css`
  z-index: 2;
  position: absolute;
  inset-inline-start: 0;
  top: 40px;
  width: 100%;
  padding: 20px;
  pointer-events: none;
`

const viewerOverlayCss = css`
  margin: 0 auto;
  width: fit-content;
  background: ${colors.gray00};
  padding: 12px;
  display: flex;
  flex-wrap: wrap;
  border-radius: 4px;
  align-items: center;
  justify-content: center;
  z-index: 2;
  pointer-events: auto;
`

export type HandleClickFn = () => void

const ImageViewerPrompt = ({ children }: { children: ReactNode }): JSX.Element | null => {
  const [isOpen, setIsOpen] = useState(Boolean(children))
  const [transitioning, setTransitioning] = useState(false)
  const [previousChildren, setPreviousChildren] = useState(children)

  useEffect(() => {
    if (children) {
      setPreviousChildren(children)
      setIsOpen((previouslyOpen) => {
        if (!previouslyOpen) setTransitioning(true)
        return true
      })
    } else {
      setIsOpen((previouslyOpen) => {
        if (previouslyOpen) setTransitioning(true)
        return false
      })
    }
  }, [children])

  return !isOpen && !transitioning ? null : (
    <OpenCloseAnimation
      className={wrapperCss}
      openStyles={{ opacity: 1, transform: 'translateY(0px)' }}
      closeStyles={{ opacity: 0, transform: 'translateY(-70px)' }}
      onCloseFinished={() => setTransitioning(false)}
      onOpenFinished={() => setTransitioning(false)}
      isOpen={isOpen}
    >
      <Elevation className={viewerOverlayCss} z={6}>
        {previousChildren}
      </Elevation>
    </OpenCloseAnimation>
  )
}

export default ImageViewerPrompt
