import type { StaticImageViewerProps } from '../static-image-viewer/StaticImageViewer'
import { type ImageStatus, mapErrorStatusToImageStatus } from './imageStatus'
import getDeepZoomInfo, { parseUrl } from './getDeepZoomInfo'
import { getImageStatus } from './imageStatus'

const DEFAULT_TILE_SIZE = 256
const DEFAULT_OVERLAP = 0
const DEFAULT_FORMAT = 'jpg'
const DEFAULT_SIZE = 7000 // Start big so the lower levels are populated

const initialImageData = {
  width: DEFAULT_SIZE,
  height: DEFAULT_SIZE,
  tileSize: DEFAULT_TILE_SIZE,
  overlap: DEFAULT_OVERLAP,
  format: DEFAULT_FORMAT,
  query: '',
  tilePath: '',
}

export type ImageData = {
  overlap?: number
  width: number
  height: number
  tileSize?: number
  tilePath?: string
  format?: string
  query?: string
}

export function isImageData(data: ImageData | ImageStatus): data is ImageData {
  return !!(data as ImageData).width
}

const getImageData = async (
  src: string,
  forceDeepZoom: boolean,
  getDeepZoomInfoCallback?: StaticImageViewerProps['getDeepZoomInfoCallback']
): Promise<ImageData | ImageStatus> => {
  const urlData = parseUrl(src, forceDeepZoom)
  if (!urlData.tilePath) {
    return new Promise((resolve) => {
      const img = new Image()
      img.addEventListener('load', () => {
        const { query } = urlData
        const { width, height } = img
        resolve({ query, width, height })
      })
      // the image error event doesn't include the error status
      // this passes the src so we can get the error type
      img.addEventListener('error', async () => {
        resolve(await getImageStatus(src))
      })
      img.src = src
    })
  }

  try {
    const deepZoomInfo = await getDeepZoomInfo(src, undefined, getDeepZoomInfoCallback)
    return { ...initialImageData, ...urlData, ...deepZoomInfo }
  } catch (error: any) /* eslint-disable-line @typescript-eslint/no-explicit-any -- catch statements are weird  */ {
    return mapErrorStatusToImageStatus(error.response?.status || error.cause?.status || 500)
  }
}

export default getImageData
