import React from 'react'
import { css } from '@linaria/core'
import ImageTile from '../components/ImageTile'
import type { ImageData } from '../utils/getImageData'
import type { Tile } from '../components/ImageTile'

/**
 * Find the ideal dimension for a tile
 * @param  srcSize    The dist width or height of an image
 * @param  zoomLevel  The zoom level to use
 * @param  topLevel   The top zoom level for this image
 * @return            The ideal tile size based on the dimensions
 *                    of the image and current and max zoom
 */
const getTargetSize = (srcSize: number, topLevel: number, zoomLevel: number): number => {
  return Math.ceil(srcSize / 2 ** (topLevel - zoomLevel))
}

/**
 * Higher-order function that determines whether tiles (in one dimension) are in view
 * @param stageStart   Either stageLeft or stageTop, depending on usage
 * @param stageEnd     Either stageRight or stageBottom, depending on usage
 * @param start        Either the top of the tile or the left of the tile
 * @param length       Either the height of the tile or the width of the tile
 * @return             Whether the given tile is fully or partially in-view
 */
const isInView =
  (stageStart: number, stageEnd: number) =>
  ([start, length]: [number, number, number]): boolean => {
    const end = start + length
    return (start <= stageEnd && start >= stageStart) || (end <= stageEnd && end >= stageStart)
  }

/**
 * Break a pixel-range into tiles
 * @method divideIntoTiles
 * @param  targetSize The ideal tile size based on the dimensions
 *                    of the image and current and max zoom
 * @param  tileSize   The tile sizes to use
 * @param  overlap    The number of pixels of overlap
 * @return            An array of size-two number-arrays, representing
 *                    The position, length of the tiles
 */
const divideIntoTiles = (targetSize: number, tileSize: number, overlap: number): [number, number, number][] => {
  const result: [number, number, number][] = []
  const targetOverlap = overlap / targetSize
  const targetTileSize = tileSize / targetSize
  const lastTileSize = (targetSize % tileSize) / targetSize || targetTileSize
  const lastTile = Math.ceil(targetSize / tileSize) - 1
  let leftLap = 0
  let rightLap = targetOverlap
  let currentTileSize = targetTileSize
  for (let i = 0; i <= lastTile; i++) {
    if (i === lastTile) {
      currentTileSize = lastTileSize
      rightLap = 0
    }
    result.push([i * targetTileSize - leftLap, currentTileSize + rightLap + leftLap, i])
    leftLap = targetOverlap
  }
  return result
}

const deepZoomImageCss = css`
  position: absolute;
  top: 0;
  left: 0;
`

type DeepZoomImageType = {
  imageData: ImageData
  level: number
  stageLeft: number
  stageRight: number
  stageTop: number
  stageBottom: number
}

const DeepZoomImage = ({
  imageData,
  level,
  stageLeft = 0,
  stageRight = 1,
  stageTop = 0,
  stageBottom = 1,
}: DeepZoomImageType): JSX.Element => {
  const { width, height } = imageData
  const longestSide = Math.max(width, height)
  const topZoomLevel = Math.ceil(Math.log2(longestSide))

  const xTiles = divideIntoTiles(
    getTargetSize(width, Math.ceil(topZoomLevel), level),
    imageData.tileSize || 256,
    imageData.overlap || 1
  ).filter(isInView(stageLeft, stageRight))

  const yTiles = divideIntoTiles(
    getTargetSize(height, Math.ceil(topZoomLevel), level),
    imageData.tileSize || 256,
    imageData.overlap || 1
  ).filter(isInView(stageTop, stageBottom))

  const tiles: Tile[] = []
  yTiles.forEach(([top, h, yIndex]) => {
    xTiles.forEach(([left, w, xIndex]) => {
      tiles.push({
        src: `${imageData.tilePath}/${level}/${xIndex}_${yIndex}.${imageData.format}${imageData.query || ''}`,
        left,
        top,
        width: w,
        height: h,
      })
    })
  })

  return (
    <div className={deepZoomImageCss} style={{ width, height }}>
      {tiles.map((tile) => (
        <ImageTile key={tile.src} tile={{ ...tile }} />
      ))}
    </div>
  )
}

export default DeepZoomImage
