import { useEffect, useState, useRef } from 'react'
import { useQueryParams } from '@fs/zion-router'
import { type ImageAttribution } from '../../utils/imageAttributionTypes'
import getImageMetaData from '../../utils/getImageMetaData'

export interface ImageMetaData extends ImageAttribution {
  error?: string
}

export default function useImageMetaData(imageApidOrArk: string | null | undefined): {
  data: ImageMetaData | null
  loading: boolean
  error: string | null
} {
  const { query } = useQueryParams()
  const groupId = query?.groupId

  const [data, setData] = useState<ImageMetaData | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const previousGroupIdRef = useRef<string | null | undefined>(undefined)

  useEffect(() => {
    let cancelled = false

    async function loadMetaData(): Promise<void> {
      if (!imageApidOrArk) {
        setData(null)
        setError(null)
        setLoading(false)
        return
      }

      // Only fetch if:
      // 1. There's a groupId AND it changed (new group = refetch)
      // 2. There's no groupId (always fetch per image)
      const hasGroupId = groupId !== null && groupId !== undefined
      const groupIdChanged = previousGroupIdRef.current !== groupId

      if (hasGroupId && !groupIdChanged && previousGroupIdRef.current !== undefined) {
        // Same group, already fetched, keep existing data in memory
        return
      }

      // Update the previous groupId
      previousGroupIdRef.current = groupId

      setLoading(true)
      setError(null)

      try {
        const result = await getImageMetaData(imageApidOrArk)
        if (!cancelled) {
          setData(result)
          setError(result.error || null)
          setLoading(false)
        }
      } catch (err) {
        if (!cancelled) {
          console.error('Failed to fetch image metadata', err)
          setError(err instanceof Error ? err.message : 'Unknown error')
          setData(null)
          setLoading(false)
        }
      }
    }

    loadMetaData()

    return () => {
      cancelled = true
    }
  }, [imageApidOrArk, groupId])

  return { data, loading, error }
}
