import React from 'react'
import { Trans, useTranslation } from 'react-i18next'
import { colors, Row, LayoutBand, H2, Subheading, Image, Alert, Separator } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import zionDebug from '@fs/zion-debug'
import UnauthorizedSvg from '../assets/unauthorized.svg'
import { type ImageMetaData } from '../../utils/getImageMetaData'

const debug = zionDebug('zion-image-viewer:RestrictedMessage') // to turn this on do this in the console: localStorage.debug = 'fs:zion-image-viewer:RestrictedMessage'

type RestrictedMessageProps = {
  imageArk: string
  metadata?: ImageMetaData
}

const RestrictedMessage = ({ imageArk, metadata }: RestrictedMessageProps): JSX.Element => {
  const [t] = useTranslation()
  const custodianUrl = metadata?.attributions?.[0]?.url || ''
  const custodianName = metadata?.attributions?.[0]?.archiveName || ''
  const validUrl =
    Boolean(custodianUrl) && /^(https?:\/\/)?(www\.)?([a-zA-Z0-9-]+\.)+[a-zA-Z]{2,5}(\/\S*)?$/.test(custodianUrl)

  debug({ imageArk, metadata, validUrl })

  return (
    <LayoutBand color={colors.gray03} style={{ minHeight: '100%' }}>
      <Separator size="lg" />
      <Row alignX="center">
        <H2 size="H3" centered>
          {t('restricted-message.heading', 'Image Restricted')}
          <Subheading>
            <Trans
              i18nKey="restricted-message.description"
              defaults="Image access is typically determined by local laws or the custodian who has the original document. This image may be visible from the <CustodianLink>custodian's website</CustodianLink>, or at the physical location."
              components={{
                CustodianLink: validUrl ? <Link to={custodianUrl} /> : <span />,
              }}
            />
          </Subheading>
        </H2>
      </Row>
      {!validUrl && (
        <>
          <Row alignX="center">
            {t('restricted-message.custodian.title', 'Custodian: {title}', { title: custodianName })}
          </Row>
          <Row alignX="center">
            <Alert type="warning">Unable to load custodian link.</Alert>
          </Row>
        </>
      )}
      <Row alignX="center">
        <Image
          src={UnauthorizedSvg}
          alt={t('restricted-message.heading', 'Image Restricted')}
          style={{ maxWidth: '750px' }}
        />
      </Row>
    </LayoutBand>
  )
}

export default RestrictedMessage
