import axios from '@fs/zion-axios'
import { sgBaseUrl } from '@fs/zion-config'
import { getImageIdFromUrl } from './getDeepZoomInfo'

type ImageStatusName = 'OK' | 'UNAVAILABLE' | 'UNAUTHORIZED'
export type ImageStatus = { status: ImageStatusName; httpStatusCode: number }
type ImagePermissionName =
  | 'RESTRICTED'
  | 'SIGN_IN_REQUIRED'
  | 'NOT_SIGNED_IN'
  | 'ON_SITE_REQUIRED'
  | 'MEMBERSHIP_REQUIRED'
  | 'UNAUTHORIZED'
export type ImagePermissionStatus = {
  status: ImagePermissionName
  themisResponse: string
}
export type ImageError = { src: string } & (ImageStatus | ImagePermissionStatus)
export type MultiImageError = ImageError & { index: number }

const mapPermissionToType = (themisResponse: string): ImagePermissionStatus => {
  let status: ImagePermissionName = 'UNAUTHORIZED'
  if (
    themisResponse.includes('ThemisPrmNoAccess') ||
    themisResponse.includes('ThemisPrmAncestry') ||
    themisResponse.includes('ThemisPrmMyHeritage') ||
    themisResponse.includes('ThemisPrmFindMyPast')
  ) {
    status = 'RESTRICTED'
  }
  if (themisResponse.includes('ThemisPrmNotSignedIn')) {
    status = 'NOT_SIGNED_IN'
  }
  if (
    themisResponse.includes('ThemisPrmPIPA') ||
    themisResponse.includes('ThemisPrmSensitive') ||
    themisResponse.includes('ThemisPrmTemple') ||
    themisResponse.includes('ThemisPrmRegisteredPatron')
  ) {
    status = 'SIGN_IN_REQUIRED'
  }
  if (themisResponse.includes('ThemisPrmLdsMember')) {
    status = 'MEMBERSHIP_REQUIRED'
  }
  if (
    themisResponse.includes('ThemisPrmAffiliate') ||
    themisResponse.includes('ThemisPrmFhlc') ||
    themisResponse.includes('ThemisPrmFhlSLC')
  ) {
    status = 'ON_SITE_REQUIRED'
  }
  return { status, themisResponse }
}

type ImageStatusCacheResult = { status?: ImageStatus; permission?: ImagePermissionStatus }
const imagePermissionCache: Record<string, ImageStatusCacheResult> = {}

const fetchImagePermission = async (imageId: string): Promise<string> => {
  const response = await axios.get(`${sgBaseUrl}/service/records/storage/dascloud/das/v2/${imageId}/permission`)
  return response.data as string
}

export async function getImageStatus(src: string): Promise<ImageStatus> {
  const existingStatus = imagePermissionCache[src]?.status
  if (existingStatus) return Promise.resolve(existingStatus)

  try {
    const response = await axios
      .create() // creates an instance so it doesn't refetch
      .head(src)
    const status: ImageStatus = { status: 'OK', httpStatusCode: response.status }
    imagePermissionCache[src] = { status }
    return status
  } catch (err: any) /* eslint-disable-line @typescript-eslint/no-explicit-any -- catch clauses only accept any or unknown */ {
    const status = mapErrorStatusToImageStatus(err.response?.status || 500)
    imagePermissionCache[src] = { status }
    return status
  }
}

export async function getImagePermission(src: string): Promise<ImagePermissionStatus> {
  const existingPermission = imagePermissionCache[src]?.permission
  if (existingPermission) return Promise.resolve(existingPermission)

  const responseData = await fetchImagePermission(getImageIdFromUrl(src))
  const permission = mapPermissionToType(responseData)
  if (imagePermissionCache[src]) {
    imagePermissionCache[src].permission = permission
  } else {
    imagePermissionCache[src] = { permission }
  }
  return permission
}

export function mapErrorStatusToImageStatus(httpStatusCode: number): ImageStatus {
  let status: ImageStatusName = 'OK'
  if (httpStatusCode === 401 || httpStatusCode === 403) status = 'UNAUTHORIZED'
  else if (httpStatusCode >= 400 && httpStatusCode < 600) status = 'UNAVAILABLE'
  return { status, httpStatusCode }
}
