import { DataTable, DataTableRow, DialogOverlay, Paragraph, Separator, type UseOverlayReturnOptions } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'

export type KeyboardShortcutOverlayProps = {
  shortcutQuickGlanceOverlay: UseOverlayReturnOptions
  hideShortcutDownloadControl?: boolean
  hideShortcutLeftRightArrows?: boolean
  showImageGrid?: boolean
}
const KeyboardShortcutOverlay = ({
  shortcutQuickGlanceOverlay,
  hideShortcutDownloadControl,
  hideShortcutLeftRightArrows,
  showImageGrid,
}: KeyboardShortcutOverlayProps): JSX.Element => {
  const { t } = useTranslation()

  const hiddenInImageGrid = [
    ['=', t('single-image-viewer.keyboard-shortcuts.zoom-in', 'Zoom In')],
    ['-', t('single-image-viewer.keyboard-shortcuts.zoom-out', 'Zoom Out')],
    ['Shift + R', t('single-image-viewer.keyboard-shortcuts.rotate-image-right', 'Rotate Image Right')],
    ['Shift + ↑', t('single-image-viewer.keyboard-shortcuts.pan-up', 'Pan Up')],
    ['Shift + ↓', t('single-image-viewer.keyboard-shortcuts.pan-down', 'Pan Down')],
    ['Shift + ←', t('single-image-viewer.keyboard-shortcuts.pan-left', 'Pan Left')],
    ['Shift + →', t('single-image-viewer.keyboard-shortcuts.pan-right', 'Pan Right')],
    hideShortcutDownloadControl
      ? null
      : ['Shift + D', t('single-image-viewer.keyboard-shortcuts.download-image', 'Download Image')],
    hideShortcutLeftRightArrows
      ? null
      : ['←', t('single-image-viewer.keyboard-shortcuts.previous-image', 'Previous Image')],
    hideShortcutLeftRightArrows ? null : ['→', t('single-image-viewer.keyboard-shortcuts.next-image', 'Next Image')],
  ]

  return (
    <DialogOverlay
      title={t('single-image-viewer.keyboard-shortcuts.title', 'Keyboard Shortcuts')}
      {...shortcutQuickGlanceOverlay}
    >
      <Paragraph size="sm">
        {t(
          'single-image-viewer.keyboard-shortcuts.description',
          'Try using these shortcuts to enhance your image viewer experience.'
        )}
      </Paragraph>
      <Separator size="sm" />
      <DataTable
        columns={[
          { label: t('single-image-viewer.keyboard-shortcuts.shortcut.table-heading', 'Shortcut'), size: 'md' },
          { label: t('single-image-viewer.keyboard-shortcuts.action.table-heading', 'Action'), size: 'lg' },
        ]}
      >
        {[
          ['Ctrl + /', t('single-image-viewer.keyboard-shortcuts.invert-image-colors', 'Invert Image Colors')],
          ['Ctrl + K', t('single-image-viewer.keyboard-shortcuts.increase-brightness', 'Increase Brightness')],
          ['Ctrl + J', t('single-image-viewer.keyboard-shortcuts.decrease-brightness', 'Decrease Brightness')],
          ['Ctrl + Shift + K', t('single-image-viewer.keyboard-shortcuts.increase-contrast', 'Increase Contrast')],
          ['Ctrl + Shift + J', t('single-image-viewer.keyboard-shortcuts.decrease-contrast', 'Decrease Contrast')],
          ...(showImageGrid ? [] : hiddenInImageGrid),
        ]
          .filter((x) => !!x)
          .map(([c1, c2]) => (
            <DataTableRow
              key={c1}
              column1={c1
                .split(' ')
                .map((token) => (token !== '+' ? <kbd style={{ fontWeight: 'bold' }}>{token}</kbd> : ' + '))}
              column2={c2}
            />
          ))}
      </DataTable>
    </DialogOverlay>
  )
}

export default KeyboardShortcutOverlay
