/**
 * Parses the image ARK identifier from a URL
 * @param src - The image URL to parse
 * @returns The ARK identifier or undefined if parsing fails
 */
export function parseImageArkFromUrl(src: string): string | undefined {
  try {
    const url = new URL(src)

    const fullUrl = url.toString()

    // Check for 3:1 pattern first
    const arkMatch = fullUrl.match(/(3:1:[A-Za-z0-9-]+)/g)
    if (arkMatch && arkMatch.length > 0) {
      return arkMatch[0]
    }

    // Check for TH- pattern for apid
    const thMatch = fullUrl.match(/(TH-[A-Za-z0-9-]+)/g)
    if (thMatch && thMatch.length > 0) {
      return thMatch[0]
    }

    return undefined
  } catch {
    // If src is not a valid URL, return undefined
    return undefined
  }
}

/**
 * Parses the image ARK identifier from an image object
 * @param image - Image object with src, srcSet, or ark property
 * @returns The ARK identifier from the image, or undefined if parsing fails
 */
export function parseImageArkFromImage(
  image:
    | {
        src?: string
        srcSet?: Record<number, string | { src: string }>
        ark?: string
      }
    | undefined
): string | undefined {
  // Check if image exists first
  if (!image) {
    return undefined
  }

  // First, check if ark is directly available on the image object
  if (image.ark) {
    return image.ark
  }

  // Try to get src directly (ImageSrc type)
  if (image.src) {
    return parseImageArkFromUrl(image.src)
  }

  // Try to get src from srcSet (ImageSrcSet type)
  if (image.srcSet) {
    const srcSetValues = Object.values(image.srcSet)
    if (srcSetValues.length > 0) {
      const firstSrc = srcSetValues[0]
      // srcSet values can be strings or objects with src property
      const url = typeof firstSrc === 'string' ? firstSrc : firstSrc?.src
      if (url) {
        return parseImageArkFromUrl(url)
      }
    }
  }

  return undefined
}
