import type { AdjustmentsValues as AdjustmentsState, AdjustmentsAction } from './Adjustments'

export const initialState: AdjustmentsState = {
  brightness: 1,
  contrast: 1,
  invert: false,
  maintainZoomPan: true,
  initialMaintainZoomPan: true,
}

export const reducer = (state: AdjustmentsState = initialState, action: AdjustmentsAction): AdjustmentsState => {
  switch (action.type) {
    case 'TOGGLE_INVERT': {
      return {
        ...state,
        invert: !state.invert,
      }
    }
    case 'TOGGLE_MAINTAIN_ZOOM_PAN': {
      return {
        ...state,
        maintainZoomPan: !state.maintainZoomPan,
      }
    }
    case 'SET_BRIGHTNESS': {
      return {
        ...state,
        brightness: action.value || state.brightness,
      }
    }
    case 'SET_CONTRAST': {
      return {
        ...state,
        contrast: action.value || state.contrast,
      }
    }
    case 'RESET_CONTROLS': {
      return {
        ...initialState,
        maintainZoomPan: state.initialMaintainZoomPan,
        initialMaintainZoomPan: state.initialMaintainZoomPan,
      }
    }
    default: {
      throw new Error(`Unhandled type in Image Viewer Controls reducer: ${action.type}`)
    }
  }
}
