import type { ComponentProps, Dispatch, ReactNode, RefObject, SetStateAction } from 'react'
import React, { createContext, useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react'
import type { ZoomPanBaseProps, ZoomPanController } from '@fs/zion-ui'
import { ZoomPanBase, calcFillZoom, colors } from '@fs/zion-ui'
import type { Point, MinMax } from '@fs/zion-ui/quarks-authorized-use-only'
import type { Rect } from '@fs/zion-ui-draggable'
import { useDraggable } from '@fs/zion-ui-draggable'
import { css } from '@linaria/core'
import { animated, useSpring } from '@react-spring/web'
import { boolAttr, useEvent } from '@fs/zion-frontend-friends'
import zionDebug from '@fs/zion-debug'
import getImageData, { type ImageData, isImageData } from '../utils/getImageData'
import type { StaticImageViewerProps } from '../static-image-viewer/StaticImageViewer'
import type { AdjustmentsValues } from './adjustments/Adjustments'
import ImageStage from '../ImageStage'
import ImageSkeleton from '../utils/ImageSkeleton'
import ImageViewerPrompt from './ImageViewerPrompt'
import PermissionMessage from './PermissionMessage'
import ImageAttribution from '../components/ImageAttribution/ImageAttribution'
import { getImagePermission, type ImageError, type ImagePermissionStatus, type ImageStatus } from '../utils/imageStatus'
import getImageMetaData, { type ImageMetaData } from '../utils/getImageMetaData'

const debug = zionDebug('zion-image-viewer:SingleImageViewerBase') // to turn this on do this in the console: localStorage.debug = 'fs:zion-image-viewer:SingleImageViewerBase'

const noOp = (): void => undefined

type ImageViewerContextProps = {
  overlayerRef: RefObject<HTMLDivElement>
  highlightColorBaseRef: RefObject<HTMLDivElement>
  controllerRef: RefObject<ZoomPanController>
  stageRef: RefObject<HTMLDivElement>
  viewerRef: RefObject<HTMLDivElement>
  setIsResizingRectangle: Dispatch<SetStateAction<boolean>>
  addOnClick: (onClick: ZoomPanBaseProps['onClick']) => void
  removeOnClick: (onClick: ZoomPanBaseProps['onClick']) => void
}

export const ImageViewerContext = createContext<ImageViewerContextProps | null>(null)
export const ImageViewerDrawingContext = createContext<boolean>(false)

const highlightAreaCss = css`
  position: absolute;
  top: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;

  &[data-drawmode] {
    cursor: crosshair;
  }
`
const drawDivCss = css`
  background-color: ${colors.green30};
  opacity: 0.5;
  position: absolute;
  top: 0;
`

const highlightColorBaseCss = css`
  position: absolute;
  z-index: 0;
  top: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  mix-blend-mode: color;
`

export type ErrorHandler = (error: ImageError) => void
export type SingleImageViewerBaseProps = {
  /** The image's source. Similar to the src attribute on an img tag */
  src: string

  /** The alt-text for this image, similar to the alt attribute of an img tag */
  alt: string

  /**
   * Any message/instructions you need to relay to the user.
   *
   * This message can be used to ask the user to draw a rectangle, or
   * do any other action.
   */
  prompt?: ReactNode

  /** This allows for customizing the image.xml request, such as adding headers or changing the request URL.
   * The returned array from this function will be used as arguments to `axios.get`.
   * See: https://axios-http.com/docs/api_intro
   */
  getDeepZoomInfoCallback?: StaticImageViewerProps['getDeepZoomInfoCallback']

  /** Whether or not the image viewer is in a state where rectangles can be drawn on
   * top of it. When in this mode, all rectangles can be captured with the `onRectangleDrawn` property.
   */
  drawingMode?: boolean

  /** This event fires whenever a user draws a rectangle. The drawingMode property must be true
   * for this event to fire.
   */
  onRectangleDrawn?: (rect: Rect) => void

  /** If this property is set, when the image viewer's zoom/pan values are reset, the image
   * will be zoomed in just enough to get rid of any letterboxing on the sides or top/bottom.
   * Basically, no stage-background will be shown.
   */
  fill?: boolean

  /** Normally, the ImageViewer tries to use information from the src attribute to decide whether
   * to go into deep-zoom mode. Setting this property forces the viewer to assume that it should
   * be in deep-zoom mode.
   */
  forceDeepZoom?: boolean

  /** Event that will fire after the ZoomPan is established and the image has been loaded. */
  onLoad?: () => void

  onError?: ErrorHandler
} & Omit<ComponentProps<'div'>, 'onClick' | 'children'>

const SingleImageViewerBase = ({
  alt,
  src,
  prompt,
  getDeepZoomInfoCallback,

  brightness = 1,
  contrast = 1,
  invert = false,
  maintainZoomPan = false,

  fill = false,
  drawingMode = false,
  forceDeepZoom = false,

  onLoad = noOp,
  onRectangleDrawn = noOp,

  onError,

  controllerRef,
  stageRef,
  viewerRef,

  overLayer,
  children,
  onClick,
  ...props
}: SingleImageViewerBaseProps & AdjustmentsValues & ZoomPanBaseProps): JSX.Element => {
  const initialZoomVal = fill ? calcFillZoom : 1
  const [isLoading, setLoading] = useState<boolean>(true)
  const [imageData, setImageData] = useState<ImageData>()
  const [errorStatus, setErrorStatus] = useState<ImageStatus | ImagePermissionStatus | null>(null)
  const [imageMetadata, setImageMetadata] = useState<ImageMetaData | undefined>()
  const overlayerRef = useRef<HTMLDivElement>(null)
  const highlightColorBaseRef = useRef<HTMLDivElement>(null)

  const handleOnload = useEvent(onLoad)
  const handleError = useEvent(onError)

  const clickHandlers = useMemo(() => new Set<ZoomPanBaseProps['onClick']>(), [])
  const handleClick = useCallback<NonNullable<ZoomPanBaseProps['onClick']>>(
    (point) => {
      onClick?.(point)
      clickHandlers.forEach((handler) => handler?.(point))
    },
    [clickHandlers, onClick]
  )
  // Fetch the deep-zoom data whenever src changes and Handle loading errors if they occur
  useEffect(() => {
    let isMounted = true
    if (!src) {
      setImageData(undefined)
      return noOp
    }
    setLoading(true)

    // Because useEffect looks at the returned value of the function provided,
    // handing an async function directly to useEffect causes problems.
    // This is a commonly accepted workaround https://github.com/facebook/react/issues/14326
    ;(async () => {
      const data = await getImageData(src, forceDeepZoom, getDeepZoomInfoCallback)
      if (!isMounted) return
      if (isImageData(data)) {
        setImageData(data)
        setErrorStatus(null)
        setLoading(false)
      } else if (data.status === 'UNAUTHORIZED') {
        const permission = await getImagePermission(src)
        setErrorStatus(permission)
        handleError({ src, ...permission })

        // Fetch metadata for restricted images to show custodian info
        try {
          const imageArk = src.split('/').pop() || src
          const metadata = await getImageMetaData(imageArk)
          if (isMounted) {
            setImageMetadata(metadata)
          }
        } catch (error) {
          console.error('Failed to fetch image metadata:', error)
          setImageMetadata(undefined)
        }
      } else {
        setErrorStatus(data)
        handleError({ src, ...data })
      }
    })()

    return function cleanUp() {
      isMounted = false
    }
  }, [src, forceDeepZoom, getDeepZoomInfoCallback, handleError])

  // Call reset and onLoad after the image data has been loaded
  useLayoutEffect(() => {
    if (imageData && !isLoading) {
      if (!maintainZoomPan) controllerRef.current.reset(true)
      handleOnload()
    }
  }, [controllerRef, imageData, isLoading, handleOnload, maintainZoomPan])

  // Set up needed context information for ImageViewerContext,
  // so that we can be aware if a rectangle is being resized
  // on a highlight.
  const [isResizingRectangle, setIsResizingRectangle] = useState(false)

  // When in drawingMode, tell ZoomPan
  useEffect(() => {
    controllerRef.current.isDrawing = drawingMode
  }, [drawingMode, controllerRef])

  // Keep track of a rectangle being drawn by the user
  // And draw a preview of that rectangle.
  const [startPoint, setStartPoint] = useState<Point | null>(null)
  const [drawingRectStyle, drawingRectSpring] = useSpring<Rect>(() => {
    return { x: 0, y: 0, width: 0, height: 0 }
  })

  const getRelativeStartPoint = useCallback(
    (point: Point): Point => {
      const { left, top } = viewerRef.current?.getBoundingClientRect() || { left: 0, top: 0 }
      const rect = { x: point.x - left, y: point.y - top }
      return rect
    },
    [viewerRef]
  )

  // Set up the dragStart, dragMove, and dragEnd events needed by useDraggabe,
  // So we can keep track of rectangles being drawn by the user and draw
  // a preview of those rectangles
  const onDragStart = useEvent((point: Point) => {
    // We don't want to listen to drag events unless
    // we're in draw mode and an existing rectangle
    // is not being resized.
    if (!drawingMode || isResizingRectangle) return

    const relativePoint = getRelativeStartPoint(point)
    setStartPoint(relativePoint)

    drawingRectSpring.set({ ...relativePoint, width: 0, height: 0 })
  })

  const onDragMove = useEvent((delta: Point) => {
    if (!drawingMode || isResizingRectangle || !startPoint) return

    const { x, y } = startPoint
    let finalX = x
    let finalY = y
    // Handle rect going negative
    if (delta.x < 0) finalX = x + delta.x
    if (delta.y < 0) finalY = y + delta.y
    const rect = { x: finalX, y: finalY, width: Math.abs(delta.x), height: Math.abs(delta.y) }
    drawingRectSpring.set(rect)
  })

  const onDragEnd = useEvent((delta: Point) => {
    if (!drawingMode || isResizingRectangle || !startPoint) return

    const { x, y } = startPoint
    let finalX = x
    let finalY = y
    // Handle rect going negative. If this happens,
    // we have to flip the rectangle and make it positive
    if (delta.x < 0) finalX = x + delta.x
    if (delta.y < 0) finalY = y + delta.y
    const rect = { x: finalX, y: finalY, width: Math.abs(delta.x), height: Math.abs(delta.y) }

    setStartPoint(null)
    onRectangleDrawn(controllerRef.current.rectFromViewToStage(rect, true))
  })

  const getBounds = useEvent((point: Point): MinMax => {
    const { x, y } = getRelativeStartPoint(point)
    const stageLeftTop = controllerRef.current.fromStageToView(0, 0, true)
    const stageRightBottom = controllerRef.current.fromStageToView(1, 1, true)

    const rect = {
      min: { x: stageLeftTop[0] - x, y: stageLeftTop[1] - y },
      max: { x: stageRightBottom[0] - x, y: stageRightBottom[1] - y },
    }
    return rect
  })

  useDraggable({
    draggableRef: stageRef,
    onDragStart,
    onDragMove,
    onDragEnd,
    getBounds,
    disabled: !drawingMode || isResizingRectangle,
    filterEvents: (event) => {
      if (!event) return true
      if ((event.target as HTMLDivElement).tabIndex === 0) return false
      return true
    },
  })

  // Memoize the context so we're memory-stable
  const imageViewerContext: ImageViewerContextProps = useMemo(
    () => ({
      overlayerRef,
      viewerRef,
      stageRef,
      controllerRef,
      highlightColorBaseRef,
      setIsResizingRectangle,
      addOnClick: (handler) => clickHandlers.add(handler),
      removeOnClick: (handler) => clickHandlers.delete(handler),
    }),
    [highlightColorBaseRef, overlayerRef, stageRef, controllerRef, viewerRef, clickHandlers]
  )

  // Don't make unnecessary requests for image permissions if there isn't an error from the api
  debug('Render: ', { errorStatus })
  if (errorStatus) {
    return <PermissionMessage {...errorStatus} src={src} metadata={imageMetadata} />
  }

  return (
    <ZoomPanBase
      data-testid={alt}
      controllerRef={controllerRef}
      viewerRef={viewerRef}
      stageRef={stageRef}
      stageRight={imageData?.width || 5000}
      stageBottom={imageData?.height || 5000}
      scrollMeansZoom
      imageMode
      onClick={handleClick}
      initialZoom={initialZoomVal}
      overLayer={
        <>
          {overLayer}
          <div ref={overlayerRef} data-drawmode={boolAttr(drawingMode)} className={highlightAreaCss} />
          {startPoint && <animated.div className={drawDivCss} style={drawingRectStyle} />}
          <ImageViewerPrompt>{prompt}</ImageViewerPrompt>
          <ImageAttribution />
        </>
      }
      {...props}
    >
      <ImageViewerContext.Provider value={imageViewerContext}>
        <ImageViewerDrawingContext.Provider value={drawingMode || isResizingRectangle}>
          {isLoading ? (
            <ImageSkeleton width={imageData?.width || 5000} height={imageData?.height || 5000} />
          ) : (
            <>
              <ImageStage
                alt={alt}
                src={src}
                data-drawmode={boolAttr(drawingMode)}
                contrast={contrast}
                brightness={brightness}
                invert={invert}
                imageData={imageData}
                controller={controllerRef.current}
                showBlurryLayer
              />
              {children}
            </>
          )}
          <div ref={highlightColorBaseRef} className={highlightColorBaseCss} data-portal="highlightColorBase" />
        </ImageViewerDrawingContext.Provider>
      </ImageViewerContext.Provider>
    </ZoomPanBase>
  )
}

export default SingleImageViewerBase
