import axios from '@fs/zion-axios'
import type { StaticImageViewerProps } from '../static-image-viewer/StaticImageViewer'

type DeepZoomData = {
  format: string
  height: number
  overlap: number
  tileSize: number
  width: number
}

type dzUrlData = {
  query: string
  dzImageUrl?: string
  tilePath?: string
}

export const isBase64 = (url: string): boolean => Boolean(url && url.match(/^data:image/))
export const isNormalImg = (url: string): boolean =>
  Boolean(url && url.match(/\.(jpg|jpeg|png|gif|tif|tiff|svg|bmp|webp)$/))
const fileExtensionRegex = /\w+\.\w+$/

/**
 * Parses a deep zoom url and returns info used to generate the tile urls.
 * @param url - url of image
 * @param type - type of image e.g. DEEPZOOM or NORMAL
 * @returns deep zoom info { dzImageUrl: 'http://familysearch.org/image.xml', query: '', tilePath: 'http://familysearch.org/image_files', }
 *   or query for normal images
 */
export const parseUrl = (url: string, forceDeepZoom: boolean): dzUrlData => {
  if (!url || isBase64(url)) return { query: '' }

  const [src, ...queries] = url.split('?')
  // If for some reason there's more than one '?' in the url, make
  // all '?'s after the first one be an '&'
  let query = queries.join('&')
  query = query && `?${query}`

  const canDetectImageTypeFromUrl = src.match(fileExtensionRegex) || isNormalImg(src)
  if ((!forceDeepZoom && !canDetectImageTypeFromUrl) || (!forceDeepZoom && isNormalImg(src))) return { query }

  const tilePath = `${src.replace(/\.\w+$/, '')}_files`
  return { dzImageUrl: src, tilePath, query }
}

const dzXmlRegex = /(ServerFormat|Format|TileSize|Overlap|Width|Height)="?(\w+)/g
const dzXmlAttSplit = /="?/
/**
 * Parse incoming image.xml file
 * @method parseDeepZoom
 * @param  {String}         xml Following spec: https://msdn.microsoft.com/fr-fr/library/cc645043(v=vs.95).aspx
 * @return {ImageData}      Needed attributes from this file
 */
export function parseDeepZoom(xml: string): DeepZoomData {
  const matches = xml.match(dzXmlRegex)
  if (!matches) throw new Error(`xml is not parsable ${xml}`)
  const dzInfo = matches
    .map((x) => x.split(dzXmlAttSplit))
    .map(([key, val]) => [key[0].toLowerCase() + key.slice(1), val])
    .reduce((result: Record<string, string | number>, [key, val]) => {
      if (key === 'format' || key === 'serverFormat') {
        result[key] = val
      } else {
        result[key] = parseInt(val, 10)
      }
      return result
    }, {})
  return {
    format: dzInfo.format as string,
    height: dzInfo.height as number,
    overlap: dzInfo.overlap as number,
    tileSize: dzInfo.tileSize as number,
    width: dzInfo.width as number,
  }
}

type ErrorWithStatus = Error & {
  status?: number
}

/**
 * Extracts identifiers from FamilySearch image URLs.
 * Examples:
 * - 's3/.../TH-7189-115002-213-80/dist.jpg' -> 'TH-7189-115002-213-80'
 * - '.../apid:TH-7703-115385-3131-73/image.xml' -> 'TH-7703-115385-3131-73'
 * - 'ark:/61903/3:1:3Q9M-CS44-1G8N' -> '3:1:3Q9M-CS44-1G8N'
 * - '.../dgs:2352342342/image.xml' -> '2352342342'
 * - '.../DGS-7703-115385-3131-73/image.xml' -> 'DGS-7703-115385-3131-73'
 * @param url - FamilySearch image URL
 * @returns Extracted identifier or empty string if not found
 */
export function getImageIdFromUrl(url: string | undefined): string {
  if (!url) return ''

  try {
    const dgsWithPrefixPattern = /(?:dgs:|apid:)([^/]+)(?=\/)/
    const dgsMatches = url.match(dgsWithPrefixPattern)

    if (dgsMatches && dgsMatches.length > 0) {
      return dgsMatches[1]
    }

    const imageIdPattern = /(TH-[^/]*)|(DGS-[^/]*)|(3:[^/]*)/g
    const matches = url.match(imageIdPattern)
    if (matches && matches?.length > 0) {
      return matches[0]
    }
  } catch (error) {
    console.error('Error parsing URL:', error)
  }
  return ''
}

/**
 * Load Deep Zoom data from a given url
 * @method getDeepZoomInfo
 * @param  {String} url - Url to use for retrieving the XML data
 * @param  {String} credentials - Either 'include', 'same-origin', or 'omit'. Default = 'include'
 * @param  {Function} getDeepZoomInfoCallback - Custom callback to use for getting the deep zoom info
 *   This allows for customizing the image.xml request, such as adding headers or changing the request URL
 * @return {Promise} - Promise that resolves with the deep zoom data
 */
async function getDeepZoomInfo(
  url: string,
  credentials = 'include',
  getDeepZoomInfoCallback?: StaticImageViewerProps['getDeepZoomInfoCallback']
): Promise<DeepZoomData> {
  try {
    const axiosArgs = getDeepZoomInfoCallback ? getDeepZoomInfoCallback(url, { credentials }) : [url, { credentials }]
    const res = await axios.get(...axiosArgs)
    if (res.status < 300 && res.data) {
      return parseDeepZoom(res.data)
    }
    return Promise.reject(
      new Error(`getDeepZoomInfo call failed with status ${res.status}`, { cause: { status: res.status } })
    )
  } catch (err) {
    return Promise.reject(
      new Error(`getDeepZoomInfo call failed: ${(err as ErrorWithStatus).status || err}`, {
        cause: { status: (err as ErrorWithStatus).status },
      })
    )
  }
}

export default getDeepZoomInfo
