import axios from '@fs/zion-axios'

/**
 * Trigger a file download (any file type) on the client without making the user click a link.
 *
 * @param  {String} fileName The name of the file to be downloaded on the client
 * @param  {String} uri      The data that will go in the file (can be any file type)
 */
async function download(fileName: string, uri: string): Promise<void> {
  // if the Android FSAndroid interface is available, use it to pass the download uri to the downloadFile method
  if (window?.FSAndroid?.downloadFile) {
    window.FSAndroid.downloadFile(uri, fileName)
    return
  }
  // @ts-expect-error - This is to detect if the page is running in the iOS app
  if (window?.webkit?.messageHandlers?.fsDownloadFile?.postMessage) {
    // @ts-expect-error - This is to detect if the page is running in the iOS app
    window.webkit.messageHandlers.fsDownloadFile.postMessage({
      fileName,
      uri,
    })
    return
  }
  const image = await axios.get(uri, { responseType: 'blob' })
  // If the image is not a png, tiff, or gif, assume it is a jpeg ($dist images are jpeg)
  const imageType = /\.(png|tiff?|gif)$/i.exec(uri) ? undefined : { type: 'image/jpeg' }
  const imageBlob = new Blob([image.data], imageType)
  const imageUrl = window.URL.createObjectURL(imageBlob)
  const a = document.createElement('a')
  a.style.display = 'none'
  a.href = imageUrl
  a.download = fileName
  document.body.appendChild(a)
  a.click()
  window.URL.revokeObjectURL(uri)
}

/**
 * Get the download URL and the file name to save to the client from the src of the single image viewer.
 *
 * @param  {String} src Source of the current image in the single image viewer
 * @return {Object}     Download URL and file name for client to download
 */
export function getFileNames(src: string): { downloadUrl: string; localFileName: string } {
  let downloadUrl = src
  let localFileName = ''
  if (src.endsWith('.dzi')) {
    const regexArr = src.match(/(^.*)\/(([\w-.:]+)(\.[\w]+$))/)
    if (regexArr) {
      const [, path, , fileWithoutExtension] = regexArr
      downloadUrl = `${path}/$dist`
      localFileName = `${fileWithoutExtension}.jpg`
    } else {
      throw new Error(`Regex fail, could not extract path and file without extension from ${src}`)
    }
  } else if (src.match(/\.(jpe?g|png|tiff?|gif)$/i)) {
    const regexArr = src.match(/(^.*)\/(([\w-.:]+)(\.[\w]+$))/)
    if (regexArr) {
      const [, , , fileWithoutExtension] = regexArr
      downloadUrl = src
      localFileName = fileWithoutExtension
    } else {
      throw new Error(`Regex fail, could not extract path and file without extension from ${src}`)
    }
  } else {
    const fileNameFull = src.includes('3:1:') ? src.split('3:1:')[1] : ''
    const fileName = fileNameFull.includes('/image.xml') ? fileNameFull.split('/image.xml')[0] : 'image'
    const newSrc = src.split('/image.xml')[0]
    downloadUrl = `${newSrc}/$dist`
    localFileName = `${fileName}.jpg`
  }

  return { downloadUrl, localFileName }
}

export const onDownload = (src: string): void => {
  const { downloadUrl, localFileName } = getFileNames(src)
  download(localFileName, downloadUrl)
}
