import type { Dispatch, ReactElement, SyntheticEvent } from 'react'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { useRandomId } from '@fs/zion-frontend-friends'
import type { NeverNullRef, ZoomPanController, UseOverlayReturnOptions } from '@fs/zion-ui'
import {
  Paragraph,
  Button,
  Divider,
  IconButton,
  MarginBox,
  Row,
  ToggleGroup,
  Toggle,
  Slider,
  useKeyboardShortcuts,
  H3,
  QuickGlanceOverlay,
  Separator,
  useOverlay,
  usePageWidth,
} from '@fs/zion-ui'
import {
  ArrowRotate,
  ControlBrightnessLess,
  ControlBrightnessMore,
  ControlContrastLess,
  ControlContrastMore,
} from '@fs/zion-icon'

import KeyboardShortcutOverlay from './KeyboardShortcutOverlay'

export type AdjustmentsActionType =
  | 'TOGGLE_INVERT'
  | 'TOGGLE_MAINTAIN_ZOOM_PAN'
  | 'SET_BRIGHTNESS'
  | 'SET_CONTRAST'
  | 'RESET_CONTROLS'

export type AdjustmentsAction = {
  type: AdjustmentsActionType
  value?: number
}

export type AdjustmentsValues = {
  /** The brightness of the image. Represents a css brightness filter, where
   * 0 means "completely black", 1 means "no adjustment", and 2 means "200% brightness"
   * (close to completely white)
   */
  brightness: number

  /** The contrast of the image. Represents a css brightness filter, where
   * 0 means "completely gray", 1 means "no adjustment", and 2 means "200% contrast"
   * (contrast is quite strong)
   */
  contrast: number

  /** Whether to invert the colors of the image. Represents a css invert filter. */
  invert: boolean

  /** Whether to reset the zoom level and image pan when switching between images */
  maintainZoomPan?: boolean

  /** The initial value of maintainZoomPan */
  initialMaintainZoomPan?: boolean
}

export type AdjustmentsProps = {
  quickGlanceOverlay: UseOverlayReturnOptions
  adjustmentsDispatch: Dispatch<AdjustmentsAction>
  adjustments: AdjustmentsValues
  controllerRef: NeverNullRef<ZoomPanController>
  adjustmentControls?: ReactElement | ReactElement[] | null
  hideMaintainZoomPan?: boolean
  hideShortcutDownloadControl?: boolean
  hideShortcutLeftRightArrows?: boolean
  onToggleMaintainZoomPan?: (newValue: boolean) => void
  showImageGrid?: boolean
}

const Adjustments = ({
  quickGlanceOverlay,
  adjustmentsDispatch,
  adjustments,
  adjustmentControls,
  controllerRef,
  hideMaintainZoomPan,
  hideShortcutDownloadControl,
  hideShortcutLeftRightArrows,
  onToggleMaintainZoomPan = () => undefined,
  showImageGrid,
}: AdjustmentsProps): JSX.Element => {
  const handleBrightnessChange = (value: number): void => adjustmentsDispatch({ type: 'SET_BRIGHTNESS', value })
  const handleContrastChange = (value: number): void => adjustmentsDispatch({ type: 'SET_CONTRAST', value })
  const { t } = useTranslation()

  const handleReset = (e: SyntheticEvent): void => {
    if (!e.defaultPrevented) controllerRef?.current.start({ rotation: controllerRef.current.initialRotation })
  }

  const handleRotate = (e: SyntheticEvent, isLeft?: string): void => {
    if (!e.defaultPrevented) {
      if (isLeft) controllerRef?.current.rotateLeft()
      else controllerRef?.current.rotateRight()
    }
  }

  useKeyboardShortcuts({
    handlers: {
      Slash: {
        ctrl: {
          action: () => adjustmentsDispatch({ type: 'TOGGLE_INVERT' }),
          title: t('single-image-viewer.adjustments.invert-image-colors.label', 'Invert Image Colors'),
        },
      },
      KeyK: {
        ctrl: {
          action: () => handleBrightnessChange(Math.min(adjustments.brightness + 0.1, 2)),
          title: t('single-image-viewer.adjustments.increase-brightness.icon-button-label', 'Increase Brightness'),
        },
        ctrlAndShift: {
          action: () => handleContrastChange(Math.min(adjustments.contrast + 0.1, 2)),
          title: t('single-image-viewer.adjustments.increase-constrast.icon-button-label', 'Increase Contrast'),
        },
      },
      KeyJ: {
        ctrl: {
          action: () => handleBrightnessChange(Math.max(adjustments.brightness - 0.1, 0)),
          title: t('single-image-viewer.adjustments.decrease-brightness.icon-button-label', 'Decrease Brightness'),
        },
        ctrlAndShift: {
          action: () => handleContrastChange(Math.max(adjustments.contrast - 0.1, 0)),
          title: t('single-image-viewer.adjustments.decrease-contrast.icon-button-label', 'Decrease Contrast'),
        },
      },
      KeyR: {
        shift: {
          action: () => controllerRef?.current.rotateRight(),
          title: t('single-image-viewer.adjustments.rotate-image-right.button', 'Rotate Image Right'),
        },
      },
    },
    enabled: true,
  })

  const brightnessSliderId = useRandomId()
  const contrastSliderId = useRandomId()

  const shortcutQuickGlanceOverlay = useOverlay()
  const { handleClick: handleClickShortcutOverlay } = shortcutQuickGlanceOverlay

  const pageWidth = usePageWidth()
  const isMobile = pageWidth({ default: true, md: false })

  const disabledInImageGridTooltip = t(
    'single-image-viewer.adjustments.disabled-in-grid-mode.tooltip',
    'Only available in single image view'
  )

  return (
    <>
      <QuickGlanceOverlay
        title={
          <Row alignY="middle">
            <H3 size="H5" growX>
              {t('single-image-viewer.adjustments.adjust-image.heading', 'Adjust Image')}
            </H3>
            {!isMobile && (
              <Button
                data-testid="keyboard-shortcuts-button"
                onClick={handleClickShortcutOverlay}
                aria-label={t('single-image-viewer.keyboard-shortcuts.button', 'Keyboard Shortcuts')}
              >
                {t('single-image-viewer.keyboard-shortcuts.button', 'Keyboard Shortcuts')}
              </Button>
            )}
          </Row>
        }
        footer={
          <Row>
            <Button
              data-testid="reset-adjustments-button"
              fullWidth
              emphasis="medium"
              onClick={(e) => {
                adjustmentsDispatch({ type: 'RESET_CONTROLS' })
                handleReset(e)
              }}
            >
              {t('single-image-viewer.adjustments.reset.button', 'Reset')}
            </Button>
          </Row>
        }
        placement="bottom-end"
        {...quickGlanceOverlay}
      >
        <Paragraph as="label" htmlFor={brightnessSliderId} size="sm">
          {t('single-image-viewer.adjustments.brightness.heading', 'Brightness')}
        </Paragraph>
        <MarginBox marginX="nano">
          <Row alignY="middle" gutters="xs">
            <IconButton
              data-testid="decrease-brightness-button"
              title={t('single-image-viewer.adjustments.decrease-brightness.icon-button-label', 'Decrease Brightness')}
              Icon={ControlBrightnessLess}
              color="gray"
              onClick={() => handleBrightnessChange(Math.max(adjustments.brightness - 0.1, 0))}
            />
            <Slider
              data-testid="brightness-slider"
              growX
              noShowProgress
              id={brightnessSliderId}
              value={adjustments.brightness}
              onChange={(value: number) => handleBrightnessChange(value)}
              min={0}
              max={2}
              step={0.1}
            />
            <IconButton
              data-testid="increase-brightness-button"
              title={t('single-image-viewer.adjustments.increase-brightness.icon-button-label', 'Increase Brightness')}
              Icon={ControlBrightnessMore}
              color="gray"
              onClick={() => handleBrightnessChange(Math.min(adjustments.brightness + 0.1, 2))}
            />
          </Row>
        </MarginBox>
        <Separator size="xs" />
        <Paragraph size="sm" as="label" htmlFor={contrastSliderId}>
          {t('single-image-viewer.adjustments.contrast.heading', 'Contrast')}
        </Paragraph>
        <MarginBox marginX="nano">
          <Row alignY="middle" gutters="xs">
            <IconButton
              data-testid="decrease-contrast-button"
              title={t('single-image-viewer.adjustments.decrease-contrast.icon-button-label', 'Decrease Contrast')}
              Icon={ControlContrastLess}
              color="gray"
              onClick={() => handleContrastChange(Math.max(adjustments.contrast - 0.1, 0))}
            />
            <Slider
              data-testid="contrast-slider"
              growX
              noShowProgress
              value={adjustments.contrast}
              id={contrastSliderId}
              onChange={(value: number) => handleContrastChange(value)}
              min={0}
              max={2}
              step={0.1}
            />
            <IconButton
              data-testid="increase-contrast-button"
              title={t('single-image-viewer.adjustments.increase-constrast.icon-button-label', 'Increase Contrast')}
              Icon={ControlContrastMore}
              color="gray"
              onClick={() => handleContrastChange(Math.min(adjustments.contrast + 0.1, 2))}
            />
          </Row>
        </MarginBox>
        <Separator size="xs" />
        <Row>
          <ToggleGroup>
            <Toggle
              data-testid="invert-colors-toggle"
              label={t('single-image-viewer.adjustments.invert-image-colors.label', 'Invert Image Colors')}
              checked={adjustments.invert}
              onChange={() => adjustmentsDispatch({ type: 'TOGGLE_INVERT' })}
            />
          </ToggleGroup>
        </Row>
        <Divider label={t('single-image-viewer.adjustments.image-rotation.heading', 'Image Rotation')} />
        <Separator size="xxs" />
        <Row wrap>
          <Button
            data-testid="rotate-left-button"
            disabled={showImageGrid}
            description={showImageGrid ? disabledInImageGridTooltip : undefined}
            Icon={ArrowRotate}
            iconReflect="horizontal"
            onClick={(e) => handleRotate(e, 'left')}
            debounce={0}
          >
            {t('single-image-viewer.adjustments.rotate-image-left.button', 'Rotate Image Left')}
          </Button>
          <Button
            data-testid="rotate-right-button"
            description={showImageGrid ? disabledInImageGridTooltip : undefined}
            disabled={showImageGrid}
            Icon={ArrowRotate}
            onClick={handleRotate}
            debounce={0}
          >
            {t('single-image-viewer.adjustments.rotate-image-right.button', 'Rotate Image Right')}
          </Button>
        </Row>
        <Separator size="xxs" />
        {!hideMaintainZoomPan && (
          <>
            <Divider label={t('single-image-viewer.adjustments.zoom-level.heading', 'Zoom Level')} marginY="xxs" />
            <ToggleGroup>
              <Toggle
                data-testid="maintain-zoom-pan-toggle"
                disabled={showImageGrid}
                label={t('single-image-viewer.adjustments.zoom-level.maintiain-zoom-level', 'Maintain Image Zoom')}
                checked={adjustments.maintainZoomPan}
                onChange={() => {
                  onToggleMaintainZoomPan(!adjustments.maintainZoomPan)
                  adjustmentsDispatch({ type: 'TOGGLE_MAINTAIN_ZOOM_PAN' })
                }}
              />
            </ToggleGroup>
          </>
        )}
        {adjustmentControls && <Row wrap>{adjustmentControls}</Row>}
      </QuickGlanceOverlay>
      <KeyboardShortcutOverlay
        shortcutQuickGlanceOverlay={shortcutQuickGlanceOverlay}
        hideShortcutDownloadControl={hideShortcutDownloadControl}
        hideShortcutLeftRightArrows={hideShortcutLeftRightArrows}
        showImageGrid={showImageGrid}
      />
    </>
  )
}

export default Adjustments
