import React from 'react'
import { Paragraph, colors, Row, DialogOverlay, Button, Separator } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { css } from '@linaria/core'
import { ContentLink } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { Trans } from 'react-i18next'
import { useAttributionContext } from './AttributionContext'

const termsOfUseStyles = css`
  padding: 8px 0;
  & p {
    padding-bottom: 0px;
  }
`

const okay = (): string => i18n.t('imageAttribution.okay', 'Okay')

function ImageAttribution(): JSX.Element | null {
  const context = useAttributionContext()

  // Don't render if context is null
  if (!context) {
    return null
  }

  const { attribution, loading, error, overlay, closeAttribution } = context
  const attributions = attribution?.attributions || []

  const sourceUrl = attributions[0]?.url || ''
  const urlPattern = /^https?:\/\/.+\..+/
  const validUrl = urlPattern.test(sourceUrl)

  // Don't render anything if not fetching or no attribution data
  if (attributions?.length < 1 || error || loading) {
    return null
  }

  return (
    <DialogOverlay
      {...overlay}
      nonClosable
      title={i18n.t('imageAttribution.subTitle', 'Image Attribution')}
      fullscreen={false}
      footer={
        <Row alignX="end">
          <Button emphasis="high" onClick={closeAttribution}>
            {okay()}
          </Button>
        </Row>
      }
    >
      <div>
        {sourceUrl && (
          <Trans
            components={{
              wrapper: <div />,
              imbeddedLink: validUrl ? <Link to={sourceUrl} target="_blank" /> : <span />,
            }}
            defaults="<wrapper>Provided by <imbeddedLink>{provider}</imbeddedLink></wrapper>"
            values={{ provider: attributions[0].archiveName }}
            i18nKey="imageAttribution.providedBy"
          />
        )}
        <Separator size="xs" />
        {attributions.map((a) => (
          <div key={`${a.url || ''}:${a.archiveName || ''}`}>
            <Paragraph size="sm">{a.url}</Paragraph>
            {a.contactInfo && <Paragraph size="sm">{a.contactInfo}</Paragraph>}
            {a.notes && (
              <div className={termsOfUseStyles}>
                <Paragraph size="sm">{a.notes}</Paragraph>
              </div>
            )}
          </div>
        ))}
        {validUrl && (
          <Row alignY="middle" gutters="xs">
            <ContentLink color={colors.gray50} />
            <Link external to={sourceUrl} target="_blank" rel="noreferrer">
              {sourceUrl}
            </Link>
          </Row>
        )}
      </div>
    </DialogOverlay>
  )
}

export default ImageAttribution
