import React from 'react'
import { useTranslation } from 'react-i18next'
import {
  Button,
  colors,
  H3,
  Image,
  LayoutBand,
  Separator,
  Row,
  Cell,
  Grid,
  useContainerWidth,
  Paragraph,
} from '@fs/zion-ui'
import { trackLink } from '@fs/zion-analytics'
import UnauthorizedSvg from '../assets/unauthorized.svg'

const hasWindow = typeof window !== 'undefined'

const SignInPrompt = (): JSX.Element => {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()

  return (
    <LayoutBand color={colors.gray03} style={{ minHeight: '100%', alignItems: 'center' }}>
      <Separator size="lg" />
      <H3 centered>{t('sign-in-prompt.heading', 'Please Sign In')}</H3>
      <Separator size="nano" />
      <Paragraph centered>
        {t(
          'sign-in-prompt.description',
          'Please sign in to determine if you have the right permissions to view this image.'
        )}
      </Paragraph>
      <Separator size="sm" />
      <Grid>
        <Cell columns={atWidth({ default: 'hide', md: 4 })}>&nbsp;</Cell>
        <Button
          columns={atWidth({ default: 12, md: 4 })}
          emphasis="high"
          fullWidth
          onClick={() => {
            trackLink(null, '/auth/familysearch/login', 'click_action', 'lo_hdr19_sign_in')
            hasWindow &&
              (window.location.href = `/auth/familysearch/login?returnUrl=${encodeURIComponent(window.location.href)}`)
          }}
        >
          {t('sign-in-prompt.sign-in', 'Sign In')}
        </Button>
        <Cell columns={atWidth({ default: 'hide', md: 4 })}>&nbsp;</Cell>
        <Cell columns={atWidth({ default: 'hide', md: 4 })}>&nbsp;</Cell>
        <Button columns={atWidth({ default: 12, md: 4 })} emphasis="medium" fullWidth to="/identity/signup/" external>
          {t('sign-in-prompt.create-account', 'Create a Free Account')}
        </Button>
      </Grid>
      <Separator size="xs" />
      <Row alignX="center" alignY="middle">
        <Button
          emphasis="low"
          external
          target="_blank"
          to="https://www.familysearch.org/help/helpcenter/article/why-are-there-access-restrictions-on-historical-records"
        >
          {t('member-message.learn-more', 'LEARN MORE')}
        </Button>
      </Row>
      <Separator size="xs" />
      <Row alignX="center">
        <Image src={UnauthorizedSvg} alt={t('restricted-message.heading', 'Image Restricted')} />
      </Row>
    </LayoutBand>
  )
}

export default SignInPrompt
