import React from 'react'
import { FullPageOverlay, ListItem, MenuOverlay, ZoomPanControlButton } from '@fs/zion-ui'
import { SingleImageViewer } from '@fs/zion-image-viewer'
import { i18n } from '@fs/zion-locale'
import { useTranslation } from 'react-i18next'
import { ContentDownload } from '@fs/zion-icon'
import useSaveToMemories from '../hooks/useSaveToMemories'
import { CHAT_ATTACHMENT_SERVICE_TYPE } from '../helpers/chatAttachmentHelper'

const DownloadMenuOverlay = ({ attachment, url }) => {
  const [t] = useTranslation()
  const saveToMemories = useSaveToMemories()

  return (
    <MenuOverlay
      menuButton={<ZoomPanControlButton label={t('chat.download.action', 'Download')} Icon={ContentDownload} />}
    >
      <ListItem
        primaryText={t('chat.download.action', 'Download')}
        data-testid="download-image"
        onClick={() => handleDownload(url)}
        dense
      />
      <ListItem
        primaryText={t('chat.save-to-memories.label', 'Save to Memories')}
        data-testid="save-to-memories"
        onClick={() => saveToMemories([attachment])}
        dense
      />
    </MenuOverlay>
  )
}

export default function ChatAttachmentFullPageOverlay({ url, id, ...props }) {
  const [t] = useTranslation()
  const attachment = {
    id,
    serviceType: CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE,
  }

  return (
    <FullPageOverlay title="" {...props} actions={[]}>
      <SingleImageViewer
        alt={t('chat.photo-attached-to-message.alt', 'Photo attached to message')}
        src={url}
        controls={<DownloadMenuOverlay attachment={attachment} url={url} />}
      />
    </FullPageOverlay>
  )
}

function handleDownload(url) {
  // Trigger a download of the image file. Based on https://stackoverflow.com/a/49917066
  const a = document.createElement('a')
  a.href = url
  // Provide a suggested filename to override the default random ID
  a.download = i18n.t('chat.download-image-filename.label', 'FamilySearch-Chat-image')
  document.body.appendChild(a)
  a.click()
  document.body.removeChild(a)
}
