import React, { useEffect, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { colors, Row, LayoutBand, H3, Subheading } from '@fs/zion-ui'
import { getSession } from '@fs/zion-session'
import zionDebug from '@fs/zion-debug'
import { RestrictedMessage, SignInPrompt, MemberMessage, LimitedAccessMessage } from '../index'
import UnauthorizedSvg from './assets/unauthorized.svg'
import UnavailableSvg from './assets/unavailable.svg'
import { getImageIdFromUrl } from '../utils/getDeepZoomInfo'
import type { ImageError } from '../utils/imageStatus'
import type { ImageMetaData } from '../utils/getImageMetaData'

const debug = zionDebug('zion-image-viewer:PermissionMessage') // to turn this on do this in the console: localStorage.debug = 'fs:zion-image-viewer:PermissionMessage'

type SessionType = {
  users: NonNullable<unknown>[]
}

const PermissionMessage = (props: ImageError & { metadata?: ImageMetaData }): JSX.Element => {
  const { status, src, metadata } = props
  const themisResponse = 'themisResponse' in props ? props?.themisResponse : undefined

  const [t] = useTranslation()
  const [session, setSession] = useState<SessionType | null>(null)

  const imageId = src ? getImageIdFromUrl(src) : ''

  useEffect(() => {
    async function checkSession(): Promise<void> {
      const sessionLocal = await getSession()
      setSession(sessionLocal)
    }
    checkSession()
  }, [status])

  debug({ status, session, imageId })
  // If app doesn't already require login, we show them the login screen here
  if (status !== 'NOT_SIGNED_IN' && !session?.users?.length) return <SignInPrompt />
  if (status === 'RESTRICTED') return <RestrictedMessage imageArk={imageId} metadata={metadata} />

  if (status === 'MEMBERSHIP_REQUIRED') return <MemberMessage />
  if (status === 'ON_SITE_REQUIRED') return <LimitedAccessMessage permissions={themisResponse} />

  const errorMessages = {
    UNAUTHORIZED: {
      header: t('ImageGroupError.unauthorizedHeader', 'Unable to Display Image'),
      subheader: t('ImageGroupError.unauthorizedSubheader', 'You do not have permission to view this image.'),
    },
    UNAVAILABLE: {
      header: t('ImageGroupError.unauthorizedHeader', 'Unable to Display Image'),
      subheader: t('ImageGroupError.unavailableSubheader', 'Try refreshing the page, or come back later.'),
    },
  }

  const currentError = errorMessages[status] || errorMessages.UNAVAILABLE
  debug({ currentError, status })

  return (
    <LayoutBand
      color={colors.gray03}
      style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
    >
      <div>
        <Row alignX="center">
          <ErrorSvg status={status} />
        </Row>
        <Row alignX="center">
          <H3 centered>
            {currentError.header}
            <Subheading>{currentError.subheader}</Subheading>
          </H3>
        </Row>
      </div>
    </LayoutBand>
  )
}

type ErrorSvgProps = {
  status: string
}

function ErrorSvg({ status }: ErrorSvgProps): JSX.Element {
  const errorSvg = status === 'UNAUTHORIZED' ? UnauthorizedSvg : UnavailableSvg
  return <img src={errorSvg} alt="" style={{ maxWidth: '750px' }} />
}

export default PermissionMessage
