const HorizontalMoveHandle = forwardRef((props, ref) => (
  <BaseDragHandle
    {...props}
    ref={ref}
    getBounds={(b, { x, y, width, height }) => ({
      min: { x: b.boundary.x - x, y: b.boundary.y - y },
      max: { x: b.boundary.x + b.boundary.width - x - width, y: b.boundary.y + b.boundary.height - y - height },
    })}
    onDragMove={(delta, { x, y }) => ({ x: x + delta.x, y })}
    cursor="auto"
  />
))

const DataTableHeaderCell = ({ column, index, stickyColumnCount, getPropsForTh }) => {
  const { label } = column
  // Label is node or object of shape { ariaLabel: 'string' }
  const isVisuallyEmpty = typeof label === 'object' && !!label.ariaLabel
  const header = isVisuallyEmpty ? null : label

  // Allow custom props and children (e.g., for SortableDataTable)
  const customProps = getPropsForTh(column, index) || {}

  return (
    <th
      scope="col"
      sticky-col={boolAttr(index < stickyColumnCount)}
      last-sticky-col={boolAttr(index + 1 === stickyColumnCount)}
      role="columnheader"
      {...customProps}
    >
      {customProps.children ?? header}
      {isVisuallyEmpty && <VisuallyHidden>{label.ariaLabel}</VisuallyHidden>}
    </th>
  )
}

const DataTableCell = ({ children, isRowHeader = false, stickyCol, lastStickyCol }) => {
  const attrs = { 'sticky-col': boolAttr(stickyCol), 'last-sticky-col': boolAttr(lastStickyCol) }
  return isRowHeader ? (
    <th {...attrs} scope="row" role="columnheader">
      {children}
    </th>
  ) : (
    <td role="cell" {...attrs}>
      {children}
    </td>
  )
}

export function DataTableRow({
  children,
  totalColumnCount,
  actionLabel,
  onClick,
  to,
  linkName,
  action,
  target,
  external,
  verticalAlign,
  selected = false,
  onExpandToggle = () => {},
  noBottomDivider = false,
  initiallyExpanded = false,
  disabled = false,
  /** [HIDDEN]: For internal Zion-UI use only */
  stickyColumnCount,
  rowLevelHeaders,
  keepVisible = false,
  ...props
}) {
  const rowRef = useRef()
  const [expandableContentHeight, setExpandableContentHeight] = useState(initiallyExpanded ? undefined : 0)
  const [rowExpanded, setRowExpanded] = useState(initiallyExpanded)
  const [rowTransitioning, setRowTransitioning] = useState(false)
  const styles = useSpring({
    height: rowExpanded ? expandableContentHeight : 0,
    onRest: () => setRowTransitioning(false),
    onStart: () => setRowTransitioning(true),
    overflow: 'hidden',
  })
  const expandableContentRef = useRef()
  const hasChildrenDisplayedRef = useRef(initiallyExpanded)
  const [t] = useTranslation()
  const rowActionRef = useRef()

  const hasChildren = Boolean(children)

  const cells = []
  for (let i = 1; i <= totalColumnCount; ++i) {
    const key = `column${i}`
    cells.push({ key, children: props[key] })
  }

  // Linkable props will have to be applied around the contents of each cell to make any sense a11y wise
  const linkProps = { to, linkName, action, external, target }
  const hasAction = !hasChildren && Boolean(to || onClick)

  // don't let checkbox clicks fire the main click action
  const handleClick = (event) => {
    if (disabled) return
    const interactiveElementFound = event.target.closest(`${focusableSelectors}, [data-interactive], [data-action]`)
    if (!(interactiveElementFound && rowRef.current?.contains(interactiveElementFound))) {
      onClick?.(event)
      if (to) {
        if (event.metaKey || event.ctrlKey) {
          window.open(to, '_blank') // CMD+click or CTRL+click opens in a new tab
        } else {
          rowActionRef.current?.click()
        }
      }
      setRowExpanded((prev) => {
        onExpandToggle(!prev)
        return !prev
      })
    }
  }

  // Determine if the children should show while hidden, before row is expanded, or if it has already been rendered
  const canShow = rowTransitioning || rowExpanded || (keepVisible && hasChildrenDisplayedRef.current)
  const showChildren = hasChildren ? canShow : false

  const updateHeight = useCallback((entry) => {
    setExpandableContentHeight(entry.target.clientHeight)
    hasChildrenDisplayedRef.current = true
  }, [])

  useResizeObserver(showChildren && expandableContentRef, updateHeight)

  return (
    <>
      <tr
        {...sanitizeProps(Object.fromEntries(Object.entries(props).filter(([key]) => !key.startsWith('column'))))}
        className={rowCss}
        role="row"
        style={{
          '--table-vertical-align': verticalAlign,
          '--gradient-direction': atTextDirection({ ltr: 'right', rtl: 'left' }),
        }}
        data-row-expandable={boolAttr(children)}
        data-row-expanded={boolAttr(showChildren)}
        interactable={boolAttr(!disabled && (onClick || to || children))}
        rowselected={boolAttr(selected)}
        onClick={handleClick}
        no-bottom-divider={boolAttr(noBottomDivider)}
        aria-disabled={disabled || undefined}
        ref={rowRef}
      >
        {hasAction && (
          <VisuallyHidden
            as="td"
            sticky-col={boolAttr(stickyColumnCount > 0)}
            style={{ position: 'sticky', insetInlineStart: 0 }}
          >
            <BaseButton
              onClick={onClick}
              {...linkProps}
              ref={rowActionRef}
              data-action
              disabled={disabled}
              tabIndex={disabled ? -1 : 0}
            >
              {actionLabel || t('common-ui:show-more.info.abbr', 'More')}
            </BaseButton>
          </VisuallyHidden>
        )}
        {cells.map(({ key, children: contents }, index) => (
          <DataTableCell
            key={key}
            stickyCol={index < stickyColumnCount}
            lastStickyCol={index + 1 === stickyColumnCount}
            isRowHeader={index + 1 === (rowLevelHeaders || stickyColumnCount)}
          >
            {contents}
          </DataTableCell>
        ))}
        {hasChildren && (
          <td className={expandRowButtonCellCss}>
            <IconButton
              color="gray"
              data-testid="DataTable_expandRowButton"
              Icon={ArrowCaret}
              iconDirection={rowExpanded ? 'up' : 'down'}
              aria-expanded={rowExpanded}
              onClick={(e) => {
                setRowExpanded((prev) => {
                  onExpandToggle(!prev)
                  return !prev
                })
                e.stopPropagation()
              }}
              title={
                rowExpanded
                  ? t('common-ui:button.collapse.action', 'Click to collapse this section')
                  : t('common-ui:button.expand.action', 'Click to expand this section')
              }
            />
          </td>
        )}
      </tr>
      {showChildren && (
        <tr
          data-expandable-content
          data-row-expanded={boolAttr(rowExpanded)}
          no-bottom-divider={boolAttr(noBottomDivider)}
          className={rowCss}
        >
          {/* Placeholder to show expandable content after sticky columns */}
          {stickyColumnCount > 0 &&
            Array(stickyColumnCount)
              .fill(null)
              .map((_, i) => (
                <td
                  key={i} // eslint-disable-line react/no-array-index-key -- not needed
                  last-sticky-col={boolAttr(i + 1 === stickyColumnCount)}
                  colSpan={stickyColumnCount}
                  sticky-col=""
                  role="cell"
                />
              ))}
          <td role="cell" sticky-col="" after-sticky-column="">
            <animated.div style={styles}>
              <div
                className={expandableContentCss}
                ref={expandableContentRef}
                after-sticky-column={boolAttr(stickyColumnCount)}
              >
                {children}
              </div>
            </animated.div>
          </td>
        </tr>
      )}
    </>
  )
}

const calcTableWidth = (columns) =>
  columns.reduce((sum, { fixedWidth, size }) => sum + (fixedWidth || columnSizes[size || 'md']), 0)

export function DataTableBase({
  children,
  columns,
  verticalAlign = 'top',
  stickyFirstColumn = false,
  gutters = 'xs',
  guttersY = gutters,
  rowLevelHeaders,
  getPropsForTh,
  caption,
  stickyHeader = true,
  ...props
}) {
  const [xScrolled, setXScrolled] = useState(false)
  const [yScrolled, setYScrolled] = useState(false)
  const [scrollable, setScrollable] = useState(false)

  const hasExpandableContent = Array.isArray(children) && children.some((child) => child.props.children)
  const hasActionContent =
    !hasExpandableContent && Array.isArray(children) && children.some((child) => child.props.onClick || child.props.to)
  const expandColWidth = hasExpandableContent ? expandableColumnWidth : 0

  // Store these in CSS vars for positioning 2nd and 3rd sticky columns
  const offset = hasActionContent ? 1 : 0
  const column1Width = columnSizes[columns[0 - offset]?.size] || columns[0 - offset]?.fixedWidth || 0
  const column2Width = columnSizes[columns[1 - offset]?.size] || columns[1 - offset]?.fixedWidth
  const column3Width = columnSizes[columns[2 - offset]?.size] || columns[2 - offset]?.fixedWidth
  const stickyColumnCount = Number(stickyFirstColumn)
  // for the record, expandable rows will never happen at the same time as hasActionContent
  const expandableOffset = (() => {
    switch (stickyColumnCount) {
      case 1:
        return column1Width
      case 2:
        return column1Width + column2Width
      case 3:
        return column1Width + column2Width + column3Width
      default:
        return 0
    }
  })()

  // Measure header size to position shadow when scrolling
  const headerRef = useRef()
  const tableWidth = calcTableWidth(columns) + expandColWidth
  const growXCount = columns.filter(({ growX }) => growX).length

  const scrollCanaryRef = useRef(null)
  const bodyRef = useRef(null)
  const tableRef = useRef(null)
  const scrollbarRef = useRef(null)
  const [containerWidth, setContainerWidth] = useState(0)

  // Scrollbar GetBounds and ContainerRef
  const scrollbarContainerRef = useRef(null)
  const getBounds = useDraggableBoundingRef(scrollbarContainerRef, 0, 12)

  // Manage Dragging ScrollBar
  const [position, setPosition] = useDraggableContainer()

  const updateScrollbarPosition = useEvent((deltaX = 0) => {
    const { clientWidth, scrollWidth } = bodyRef.current
    const maxScroll = scrollWidth - clientWidth
    if (maxScroll <= 0) return

    // Get normalized scroll position accounting for RTL
    const textDirection = atTextDirection({ ltr: 1, rtl: -1 })
    const normalizedScroll = bodyRef.current.scrollLeft * textDirection + deltaX

    // Calculate ratio between 0 and 1
    const ratio = Math.max(0, Math.min(normalizedScroll / maxScroll, 1))

    // Apply scroll position
    const scrollLeft = ratio * maxScroll * textDirection
    bodyRef.current.scrollLeft = scrollLeft
    headerRef.current.scrollLeft = scrollLeft

    // Update thumb
    const thumbWidth = Math.max((clientWidth / scrollWidth) * clientWidth, 40)
    const thumbTravel = clientWidth - thumbWidth
    const thumbX = ratio * thumbTravel

    setPosition({
      x: thumbX * textDirection,
      y: 0,
      width: thumbWidth,
      height: 12,
    })

    // Update scroll state
    setXScrolled(ratio > 0)
  })

  useResizeObserver(bodyRef, () => {
    setScrollable(bodyRef.current.scrollWidth > bodyRef.current.clientWidth)
    setContainerWidth(bodyRef.current.clientWidth)
    updateScrollbarPosition()
  })

  // Sets Position of ScrollBar on Scroll event
  const handleScroll = useEvent((event) => {
    // on Windows, when holding down the shift key, it still emits a deltaY when it should be deltaX
    let delta = event.deltaX
    if (!delta && event.shiftKey) {
      delta = event.deltaY
    }
    if (delta !== 0) {
      event.preventDefault()
    }
    updateScrollbarPosition(delta)
  })

  const handleChange = useEvent(({ x, width }) => {
    const { clientWidth, scrollWidth } = bodyRef.current
    const maxScroll = scrollWidth - clientWidth
    if (maxScroll <= 0) return

    const textDirection = atTextDirection({ ltr: 1, rtl: -1 })

    // Calculate ratio from thumb position
    const thumbTravel = clientWidth - width
    const ratio = Math.max(0, Math.min((x * textDirection) / thumbTravel, 1))

    // Update scroll position
    const scrollLeft = ratio * maxScroll * textDirection
    bodyRef.current.scrollLeft = scrollLeft
    headerRef.current.scrollLeft = scrollLeft

    // Update scroll state
    setXScrolled(ratio > 0)
  })

  // Manages Horizontal Scroll with Touch Events (Mobile)
  const [touchStartX, setTouchStartX] = useState(0)
  const [touchStartY, setTouchStartY] = useState(0)
  const [scrollStartX, setScrollStartX] = useState(0)

  const handleTouchStart = (event) => {
    setTouchStartX(event.touches[0].clientX)
    setTouchStartY(event.touches[0].clientY)
    setScrollStartX(bodyRef.current.scrollLeft)
  }

  // Handle Touch Move needs to be debounced by requestAnimationFrame
  const animationFrameIdRef = useRef(null)
  const handleTouchMove = useCallback(
    (event) => {
      if (animationFrameIdRef.current) {
        return
      }
      animationFrameIdRef.current = requestAnimationFrame(() => {
        const touchX = event.touches[0].clientX
        const touchY = event.touches[0].clientY
        const deltaX = touchStartX - touchX
        const deltaY = touchStartY - touchY

        if (Math.abs(deltaX) > Math.abs(deltaY)) {
          if (event.cancelable) {
            event.preventDefault()
          }
          const totalDelta = scrollStartX + deltaX - bodyRef.current.scrollLeft
          updateScrollbarPosition(totalDelta)
        }
        animationFrameIdRef.current = null
      })
    },
    [scrollStartX, touchStartX, touchStartY, updateScrollbarPosition]
  )

  // Manages Horizontal Scroll with Keyboard (Arrow Keys)
  const handleKeyDown = (event) => {
    const scrollSpeed = 40
    if (event.key === 'ArrowRight') {
      updateScrollbarPosition(scrollSpeed)
    } else if (event.key === 'ArrowLeft') {
      updateScrollbarPosition(-scrollSpeed)
    }
  }

  // Listener for mousewheel event, must be handled using useEffect since event listener cannot be passive
  useEffect(() => {
    const tableElement = tableRef.current
    tableElement.addEventListener('wheel', handleScroll, { passive: false })
    tableElement.addEventListener('touchmove', handleTouchMove, { passive: false })
    return () => {
      tableElement.removeEventListener('wheel', handleScroll)
      tableElement.removeEventListener('touchmove', handleTouchMove)
    }
  }, [handleScroll, handleTouchMove])

  // Manage Scroll Canary for Table styling
  useObserver(scrollCanaryRef, (entry) => setYScrolled(!entry.isIntersecting))

  // Calculate Grid Template Column Property from all columns
  let finalGridTemplateColumnsProperty = hasActionContent ? '0 ' : ''
  const growXExists = columns.filter((column) => 'growX' in column).length

  columns.forEach((column) => {
    const size = column.fixedWidth ? String(column.fixedWidth) : String(columnSizes[column.size || 'md'])
    if (!growXExists || 'growX' in column) {
      finalGridTemplateColumnsProperty += `minmax(${size}px, 1fr) `
    } else {
      finalGridTemplateColumnsProperty += `${size}px `
    }
  })
  if (hasExpandableContent) {
    finalGridTemplateColumnsProperty += `${expandableColumnWidth}px` // For Expandable Icon
  }

  return (
    <ResponsiveProvider>
      <div ref={scrollCanaryRef} />
      <GridStart>
        <GutterBox
          as="table"
          role="table"
          ref={tableRef}
          tabIndex={scrollable ? 0 : undefined}
          aria-rowcount={columns.length}
          onTouchStart={handleTouchStart}
          onKeyDown={handleKeyDown}
          guttersX={gutters}
          guttersY={guttersY}
          {...sanitizeProps(props)}
          className={tableCss}
          style={{
            '--table-width': `${containerWidth}px`,
            '--table-vertical-align': verticalAlign,
            '--table-column-1-width': `${column1Width}px`,
            '--table-column-2-width': `${column2Width}px`,
            '--table-column-3-width': `${column3Width}px`,
            '--table-expandable-offset': `${expandableOffset}px`,
            '--grid-template-columns': finalGridTemplateColumnsProperty,
            '--thead-position': stickyHeader ? 'sticky' : 'static',
            // When the table stretches due to its minWidth, the extra width is usually allocated evenly to every column, but when one or more columns have `growX`, this extra space is allocated evenly between every column that has `growX`. We need to add this amount to the columns' width:`size` instead of using width:auto to keep the columns with growX from shrinking or growing too much. ( min-width does not work on table cells )
            // Note: This calculation is (( table's min-width - its width - its padding ) / the amount of columns with `growX`) and is always >= 0px
            '--remaining-space': `max(((var(--table-min-width) - ${tableWidth}px - var(--gutters-x)) / ${growXCount}), 0px)`,
          }}
          sticky-columns={stickyColumnCount || undefined}
          x-scrolled={boolAttr(xScrolled)}
          y-scrolled={boolAttr(yScrolled)}
        >
          {caption && (
            <caption>
              <VisuallyHidden>{caption}</VisuallyHidden>
            </caption>
          )}
          <thead ref={headerRef} role="rowgroup">
            <tr className={rowCss} role="row">
              {hasActionContent && (
                <VisuallyHidden
                  as="td"
                  sticky-col={boolAttr(stickyColumnCount > 0)}
                  style={{ position: 'sticky', insetInlineStart: 0 }}
                />
              )}
              {columns?.map((column, index) => (
                <DataTableHeaderCell
                  column={column}
                  index={index}
                  key={index} // eslint-disable-line react/no-array-index-key -- no other way to do this.
                  stickyColumnCount={stickyColumnCount}
                  getPropsForTh={getPropsForTh}
                />
              ))}
              {hasExpandableContent ? <td className={expandRowButtonCellCss} /> : null}
            </tr>
          </thead>
          <tbody ref={bodyRef} role="rowgroup">
            {Children.map(
              children,
              (child) =>
                child && cloneElement(child, { totalColumnCount: columns.length, stickyColumnCount, rowLevelHeaders })
            )}
          </tbody>
        </GutterBox>
        {scrollable && (
          <div className={scrollBarContainerCss} ref={scrollbarContainerRef}>
            <DraggableContainer
              ref={scrollbarRef}
              className={scrollBarCss}
              getBounds={getBounds}
              position={position}
              setPosition={setPosition}
              onAnimationChange={handleChange}
            >
              <HorizontalMoveHandle className={scrollHandleCss} noStretchy />
            </DraggableContainer>
          </div>
        )}
      </GridStart>
    </ResponsiveProvider>
  )
}

const defaultGetPropsForTh = () => ({})

export function DataTable(props) {
  return <DataTableBase {...props} getPropsForTh={defaultGetPropsForTh} />
}

DataTable.propTypes = {
  /** `DataTableRow` instances */
  children: PropTypes.node,

  /** column configuration array. Each entry binds to that column position. Note that `fixedWidth` will interfere with peeking.
   * Object of the following per column: <br/>
   * - `label<Node | { ariaLabel: String }>`: _the label string, JSX, or object for the column header._ <br/>
   * - `size<String>`: _the width size that column takes._ <br/>
   * - `fixedWidth<String|Number>`: _the constant width that column takes. **It is recommended you use `size` where possible**_
   * - `growX<Boolean>`: _In situations where the table has more than enough room to fit all columns, each column will stretch a little to take up the remaining space. If this is not desired, you can add `growX: true` to specify which columns will grow. NOTE: Once you do this on one column, all other columns will stop growing. Can be used on more than one column at a time._
   */
  columns: PropTypes.arrayOf(
    PropTypes.shape({
      label: PropTypes.oneOfType([
        PropTypes.node.isRequired,
        PropTypes.shape({ ariaLabel: PropTypes.string.isRequired }),
      ]).isRequired,
      size: PropTypes.oneOf(['xxs', 'xs', 'sm', 'md', 'lg', 'xl', 'xxl']),
      fixedWidth: PropTypes.number,
      growX: PropTypes.bool,
    }).isRequired
  ).isRequired,

  /**
   * 1-based index of the column to use as row-level headers (affects semantics and a11y, not appearance).
   * Enabling sticky columns will automatically use the last sticky column as row-level headers, but this can still be overriden.
   */
  rowLevelHeaders: PropTypes.number,

  /** Whether to make the left-most column (if boolean) or columns (if number) sticky. */
  stickyFirstColumn: PropTypes.oneOf([true, false, 1, 2, 3]),

  /** Makes the header sticky (default true). */
  stickyHeader: PropTypes.bool,

  /** If you want multiple consecutive rows to appear as if they are part of one row, turn off the borders between them. */
  noBottomDivider: PropTypes.bool,

  /** The vertical alignment of the rows */
  verticalAlign: PropTypes.oneOf(['baseline', 'top', 'middle', 'bottom']),

  /** Gutter distance between cells */
  gutters: PropTypes.oneOf(['lg', 'md', 'sm', 'xs', 'xxs', 'nano']),

  /** Vertical gutter distance between cells (matches 'gutters' if not specified) */
  guttersY: PropTypes.oneOf(['lg', 'md', 'sm', 'xs', 'xxs', 'nano']),

  /** Visually-hidden descriptive text for the table */
  caption: PropTypes.string,
}

DataTableRow.propTypes = {
  /** The content of each column in the row. The number represents the respective cell slot it will take up. */
  'column1 column2 ... column*': PropTypes.node,

  /** Content to be rendered in an expandable area beneath the row */
  children: PropTypes.node,

  /** Custom label for the row action (to or onClick). Defaults to "More" */
  actionLabel: PropTypes.string,

  /** The callback for when the row is clicked */
  onClick: PropTypes.func,

  /** Link the table row to another page */
  to: PropTypes.string,

  /** Show this item as selected */
  selected: PropTypes.bool,

  /** Disable the row, preventing click interactions */
  disabled: PropTypes.bool,

  /** Callback for when the row is expanded/collapsed. One parameter is passed: a boolean for whether it is expanded (`true`) or collapsed (`false`) */
  onExpandToggle: PropTypes.func,

  /** Whether the row should be expanded by default */
  initiallyExpanded: PropTypes.bool,
}
