import type { ReactNode } from 'react'
import React, { useCallback, useRef, useState, useEffect } from 'react'
import { css } from '@linaria/core'
import { shallowEqual, useAnimationFrames } from '@fs/zion-frontend-friends'
import type { ZoomPanMath, ZoomPanValues } from '@fs/zion-ui'
import { useWidth } from '@fs/zion-ui/quarks-authorized-use-only'
import DeepZoomImage from './single-image-viewer/DeepZoomImage'
import type { ImageData } from './utils/getImageData'

const imageStageCss = css`
  position: relative;
  width: 500px;
  height: 500px;
  img {
    display: block;
    position: absolute;
  }
`

const makeFilterString = (name: string, amount: number, defaultValue: number): string =>
  amount !== defaultValue ? `${name}(${amount * 100}%)` : ''

const numericSort = (a: number, b: number): number => a - b

export type ImageStageProps = {
  src: string
  alt?: string
  contrast?: number
  brightness?: number
  invert?: boolean
  imageData?: ImageData
  controller: { math?: ZoomPanMath; get: () => ZoomPanValues }
  showBlurryLayer?: boolean
  children?: ReactNode
}

const ImageStage = ({
  alt = '',
  src,
  contrast = 1,
  brightness = 1,
  invert = false,
  imageData,
  controller,
  showBlurryLayer = true,
  children,
  ...props
}: ImageStageProps): JSX.Element | null => {
  const width = useWidth()
  const currentWidth = useRef(width)
  const prevWidth = useRef(0)

  const [values, setValues] = useState(controller.get())
  const prevValues = useRef(values)

  const filter = [
    makeFilterString('brightness', brightness, 1),
    makeFilterString('contrast', contrast, 1),
    makeFilterString('invert', invert ? 1 : 0, 0),
  ]
    .join(' ')
    .trim()

  useEffect(() => {
    currentWidth.current = width
  }, [width])
  // Prevents over-updating of values, so that we can:
  //   1) Ignore new objects containing the same values
  //   2) Force a re-render when the width of the browser changes
  const updateValues = useCallback(() => {
    const gotValues = controller.get()
    if (!shallowEqual(prevValues.current, gotValues) || prevWidth.current !== currentWidth.current) {
      prevWidth.current = currentWidth.current
      prevValues.current = gotValues
      setValues(gotValues)
    }
  }, [controller])
  useAnimationFrames(updateValues)

  let imageStage: ReactNode

  if (imageData?.tilePath) {
    if (!controller.math) return null

    let dynamicImageStage: ReactNode = null // The tiles of imageStageNess

    const { width: stageWidth, height: stageHeight } = imageData
    const { aspectX, viewWidth, viewHeight } = controller.math.calcHelperValues()
    const targetScale = (values.zoom * aspectX * viewWidth) / stageWidth
    const longestSide = Math.max(stageWidth, stageHeight)
    const topZoomLevel = Math.ceil(Math.log2(longestSide))
    const idealZoomLevel = Math.min(topZoomLevel, topZoomLevel + Math.ceil(Math.log2(targetScale)))

    if (
      idealZoomLevel > 9 || // We need more detail than what's shown on the blurryLayer.
      !showBlurryLayer || // We need to render this anyway, because there's no blurryLayer.
      topZoomLevel < 9 // We won't be showing the blurryLayer, because level 9 isn't available.
    ) {
      let [stageLeft, stageTop] = controller.math.fromViewToStage(0, 0, values)
      let [stageRight, stageBottom] = controller.math.fromViewToStage(viewWidth, viewHeight, values)

      // In case we are rotated, we need to swap left,right to make left < right
      ;[stageLeft, stageRight] = [stageLeft, stageRight].sort(numericSort)
      // In case we are rotated, we need to swap top,bottom to make top < bottom
      ;[stageTop, stageBottom] = [stageTop, stageBottom].sort(numericSort)

      dynamicImageStage = (
        <DeepZoomImage
          imageData={imageData}
          level={idealZoomLevel}
          stageLeft={stageLeft}
          stageRight={stageRight}
          stageTop={stageTop}
          stageBottom={stageBottom}
        />
      )
    }

    // assemble the base level 9 (blurryLayer) with the optimal zoom layer.
    imageStage = (
      <>
        {showBlurryLayer && topZoomLevel >= 9 && (
          <DeepZoomImage imageData={imageData} level={9} stageLeft={0} stageRight={1} stageTop={0} stageBottom={1} />
        )}
        {dynamicImageStage}
      </>
    )
  } else {
    imageStage = <img alt={alt} src={src} />
  }

  return (
    <div {...props} className={imageStageCss} style={{ width: imageData?.width, height: imageData?.height, filter }}>
      {imageStage}
      {children}
    </div>
  )
}

export default ImageStage
