import { useEffect } from 'react'

const hasWindow = typeof window !== 'undefined'

/**
 * A hook for running code on every animation frame.
 *
 * **WARNING**: This hook should be used with caution, since it can cause performance issues.
 * Don't use it with functions that run slowly or cause a re-render.
 *
 * @param task the task to run
 */
const useAnimationFrames = (task: () => void): void => {
  useEffect(() => {
    let currentAnimationRequest: number | null = null

    const update = (): void => {
      task()
      currentAnimationRequest = hasWindow ? requestAnimationFrame(update) : null
    }
    update()
    return () => {
      if (hasWindow) cancelAnimationFrame(currentAnimationRequest as number)
    }
  }, [task])
}

export default useAnimationFrames
